/* ============================================================
   French formatting
   ============================================================ */
const nf = (x, d = 2) => Number(x).toLocaleString("fr-FR", { minimumFractionDigits: d, maximumFractionDigits: d });
function fmtV(v) { return nf(Math.abs(v) < 1e-9 ? 0 : Math.abs(v), 2) + " V"; }
function fmtVsig(v) { return nf(Math.abs(v) < 5e-3 ? 0 : v, 1) + " V"; }
function fmtA(i) {
  const a = Math.abs(i);
  if (a >= 1) return nf(a, 2) + " A";
  const mA = a * 1000;
  return (mA >= 100 ? nf(mA, 0) : nf(mA, 1)) + " mA";
}
function fmtR(r) { return r >= 1000 ? nf(r / 1000, r % 1000 === 0 ? 0 : 1) + " kΩ" : Math.round(r) + " Ω"; }
function fmtP(p) { const a = Math.abs(p); return a >= 1 ? nf(a, 2) + " W" : nf(a * 1000, 0) + " mW"; }
function fmtCap(uf) { return uf >= 1000 ? nf(uf / 1000, uf % 1000 === 0 ? 0 : 1) + " mF" : Math.round(uf) + " µF"; }
function fmtInd(h) { return h >= 1 ? nf(h, h % 1 === 0 ? 0 : 1) + " H" : Math.round(h * 1000) + " mH"; }
function fmtFreq(f) { return f >= 1 ? nf(f, f % 1 === 0 ? 0 : 1) + " Hz" : nf(f * 1000, 0) + " mHz"; }
function fmtWh(j) { const wh = j / 3600; if (wh < 1) return nf(wh * 1000, wh * 1000 >= 100 ? 0 : 1) + " mWh"; if (wh < 1000) return nf(wh, wh >= 100 ? 0 : 1) + " Wh"; return nf(wh / 1000, 2) + " kWh"; }
function fmtEur(e) { return nf(e, e >= 1 ? 2 : 3).replace(/\u00A0/g, " ") + " €"; }
// Bus values may be Number (<=52 bits) or BigInt (64-bit) — these accept both.
const bigOf = (v) => (typeof v === "bigint" ? v : BigInt(Math.trunc(Number(v) || 0)));
function busDec(v) { return bigOf(v).toString(); }
function busHex(v) { return "0x" + bigOf(v).toString(16).toUpperCase(); }
function busBit(v, k) { return Number((bigOf(v) >> BigInt(k)) & 1n); }

