function defaultName(c, comps) {
  const info = TYPE_LABELS[c.type] || { base: "Composant", short: "X" };
  const same = comps.filter((x) => x.type === c.type);
  if (same.length <= 1) return info.base;
  return info.short + (same.findIndex((x) => x.id === c.id) + 1);
}
function compLabel(c, comps) { const n = (c.name || "").trim(); return n || defaultName(c, comps); }

