import { PIN, SPDT_SP, chipDims, pinsOf, buildPinMap, BBOARD } from "./geometry.js";
function lampColor(b) {
  const o = [26, 34, 48], n = [255, 206, 84];
  const ch = (i) => Math.round(o[i] + (n[i] - o[i]) * b);
  return "rgb(" + ch(0) + "," + ch(1) + "," + ch(2) + ")";
}
function voltColor(t) {
  t = Math.max(0, Math.min(1, t));
  const lo = [74, 144, 226], hi = [255, 93, 114];
  const ch = (i) => Math.round(lo[i] + (hi[i] - lo[i]) * t);
  return "rgb(" + ch(0) + "," + ch(1) + "," + ch(2) + ")";
}
const litLampIds = (comps, sim) =>
  comps.filter((c) => c.type === "lamp" && sim?.ok && Math.abs(sim.result[c.id]?.power || 0) > 0.05).map((c) => c.id);

/* current leaving a pin toward the wire (to orient the particles) */
function pinOutCurrent(c, res, idx) {
  if (!res) return 0;
  if (c.type === "battery" || c.type === "acsource") { const I = Math.abs(res.current); const s = res.current < 0 ? -1 : 1; return (idx === 0 ? -I : I) * s; }
  if (c.type === "npn") { const cur = idx === 0 ? (res.ic || 0) : idx === 1 ? (res.ib || 0) : (res.ie || 0); return -cur; }
  if (c.type === "nmos" || c.type === "pmos") { const i = res.id || 0; return idx === 0 ? -i : idx === 2 ? i : 0; }
  if (c.type === "opamp") { return idx === 2 ? -(res.current || 0) : 0; }
  if (c.type === "isource") { const I = res.current || 0; return idx === 0 ? I : -I; }
  if (["resistor", "lamp", "ammeter", "pot", "motor", "fuse", "capacitor", "inductor", "wattmeter", "diode", "led", "zener"].includes(c.type)) {
    const i01 = res.current; // courant pin0 -> pin1 à travers le composant
    return idx === 0 ? -i01 : i01;
  }
  if (c.type === "multimeter" && c.mode === "A") { const i01 = res.current; return idx === 0 ? -i01 : i01; }
  return 0; // voltmètre, interrupteur (nœud fusionné)
}

