const ARD_BB_DEFAULT = `// Breadboard : bouton sur D2, LED ou lampe sur D13.
// Cable : D2 -> bouton -> GND ; D13 -> (resistance ->) LED/lampe -> GND.
// Appuie sur le bouton (ferme l'interrupteur) pour allumer.
void setup() {
  pinMode(2, INPUT_PULLUP);
  pinMode(13, OUTPUT);
}
void loop() {
  if (digitalRead(2) == LOW) digitalWrite(13, HIGH);
  else digitalWrite(13, LOW);
}`;
const ARD_CAT = { cat: "Programmable", icon: Cpu, items: [{ type: "arduino", name: "Arduino", desc: "Carte programmable : ses broches pilotent et lisent le circuit. Ecris le code (bouton Code), cable 5V/GND/D2-D13/A0-A5 a tes composants, puis Televerse. Une sortie HIGH = 5 V ; une entree lit la tension du noeud.", defaults: { code: ARD_BB_DEFAULT } }] };
CATALOG.push(ARD_CAT); CATALOG_E.push(ARD_CAT); CATALOG_N.push(ARD_CAT);

