const CATALOG_A = [];
const LEVELS_A = {
  a1: { simple: "Imagine un robot à qui tu donnes deux listes de consignes. La première, il la lit une seule fois en se réveillant (setup) : « mets tes chaussures, allume ta lampe ». La seconde, il la refait sans arrêt (loop) : « avance, regarde, recommence ». La carte Arduino fonctionne exactement comme ça.",
    technique: "Le microcontrôleur (un ATmega328P sur l'Uno) exécute le code compilé en partant de setup() une fois, puis appelle loop() en boucle infinie. Les broches numériques (0–13) et analogiques (A0–A5) sont les entrées/sorties ; l'alimentation et la programmation passent par l'USB. Le sketch est compilé en C++ puis flashé en mémoire programme (Flash).",
    expert: "L'environnement Arduino enveloppe le toolchain AVR-GCC : un main() fourni par le core appelle init(), puis setup(), puis boucle sur loop(). Le code réside en Flash (32 Ko sur l'Uno), les variables en SRAM (2 Ko). Sans système d'exploitation, loop() monopolise le CPU : tout est coopératif, et un delay() bloquant gèle réellement le programme." },
  a2: { simple: "Une broche en sortie, c'est un interrupteur commandé par le programme. digitalWrite(..., HIGH) c'est « je pousse l'interrupteur » (courant qui passe, LED allumée) ; LOW c'est « je relâche » (éteint). La broche 13 a déjà une petite LED sur la carte pour s'entraîner sans rien brancher.",
    technique: "pinMode() configure le registre de direction de la broche. digitalWrite() écrit dans le registre de port : HIGH ≈ Vcc (5 V sur l'Uno), LOW = 0 V. Le courant maximal par broche est d'environ 20 mA ; une LED se branche en série avec une résistance (typiquement 220–330 Ω) pour limiter ce courant.",
    expert: "Sur l'AVR, pinMode/digitalWrite manipulent DDRx/PORTx bit à bit (la broche 13 = PB5). digitalWrite est relativement lent (lecture-modification-écriture + résolution de la broche) ; pour du bit-banging rapide on attaque directement les registres. En INPUT, écrire HIGH active le pull-up interne (~20–50 kΩ) — d'où INPUT_PULLUP." },
  a3: { simple: "Clignoter, c'est : allumé… j'attends… éteint… j'attends… et je recommence. delay(500) veut dire « attends une demi-seconde sans rien faire ». En répétant ce motif dans loop(), la LED clignote toute seule.",
    technique: "delay(ms) suspend l'exécution en comptant les millisecondes via le timer interne. La période de clignotement = somme des délais (500 + 500 = 1000 ms → 1 Hz). delay() est bloquant : aucune autre tâche ne progresse pendant l'attente, ce qui pose problème dès qu'on veut lire des entrées en parallèle.",
    expert: "delay() s'appuie sur micros()/le Timer0 et n'autorise que les interruptions à s'exécuter. Pour de la concurrence coopérative on le remplace par un motif non bloquant : if (millis() - last >= interval) { last += interval; /* basculer */ }. Cela libère loop() et évite la dérive si l'on incrémente last plutôt que de le remettre à millis()." },
  a4: { simple: "Un bouton, c'est un interrupteur que le programme surveille. Mais une broche d'entrée toute seule « hésite » entre 0 et 1. La ruse INPUT_PULLUP la cale à 1 au repos ; quand tu appuies, elle tombe à 0. Donc « appuyé » se lit comme LOW (0).",
    technique: "INPUT_PULLUP active le pull-up interne (~20–50 kΩ) qui fixe la broche à HIGH au repos. Le bouton, câblé broche↔masse, force LOW à l'appui. Sans tirage, l'entrée haute impédance flotte et digitalRead renvoie des valeurs aléatoires. Un rebond mécanique peut générer plusieurs transitions ; on l'atténue par anti-rebond logiciel ou matériel.",
    expert: "Le pull-up interne AVR (PORTx=1 quand DDRx=0) évite un composant externe mais sa valeur élevée le rend sensible au bruit sur de longues pistes. Le rebond se traite par debouncing (filtrage temporel sur millis(), machine à états, ou RC + trigger de Schmitt). Pour des lectures critiques on préfère une interruption sur front (attachInterrupt) plutôt que du polling." },
  a5: { simple: "Le moniteur série, c'est un petit chat écrit entre la carte et l'écran. Tu ouvres la conversation une fois (Serial.begin), puis la carte t'envoie des messages avec Serial.println. Pratique pour savoir ce qu'elle « pense » quand elle ne fait pas ce que tu veux.",
    technique: "Serial.begin(débit) initialise la liaison série à la vitesse donnée (bauds) ; émetteur et récepteur doivent s'accorder (9600 par défaut). print/println sérialisent texte et nombres (les flottants avec 2 décimales par défaut). C'est l'instrument de débogage privilégié, faute de débogueur pas-à-pas sur la cible.",
    expert: "L'UART matériel transmet en série asynchrone (start/données/stop) à la vitesse choisie ; sur l'Uno il partage les broches 0/1 avec l'USB. print/println passent par un buffer d'émission piloté par interruption ; flush() attend la vidange. Coût temporel : ~1 ms par caractère à 9600 bauds — des affichages massifs dans loop() ralentissent le programme." },
  a6: { simple: "Une broche numérique ne voit que « éteint » ou « allumé ». Une broche analogique, elle, voit toutes les nuances entre les deux — comme un variateur plutôt qu'un interrupteur. analogRead te donne cette nuance sous forme d'un nombre de 0 à 1023 : 0 sans tension, 1023 au maximum (5 V).",
    technique: "Les broches A0–A5 sont reliées à un CAN à approximations successives 10 bits (1024 niveaux). analogRead() renvoie round(Vin / Vref × 1023) avec Vref = 5 V par défaut (modifiable via analogReference). Quantum ≈ 4,9 mV. Une conversion prend ~100 µs ; l'impédance de source doit rester faible (< 10 kΩ).",
    expert: "Le CAN SAR multiplexe une seule cellule sur les 6 entrées. Vref peut être AVcc, la référence interne 1,1 V, ou AREF externe. Erreurs : bruit de quantification (q/√12), couplage du multiplexeur (prévoir un délai ou une lecture à blanc après changement de canal), chute sur l'impédance d'entrée. Pour une source haute impédance, on ajoute un suiveur." },
  a7: { simple: "Certains capteurs sont des résistances qui changent de valeur : la photorésistance laisse passer plus de courant en pleine lumière, la thermistance quand il fait chaud. Pour que l'Arduino le « sente », on transforme cette résistance en tension avec un petit montage (le pont diviseur), puis on lit avec analogRead.",
    technique: "LDR et NTC sont des résistances dépendant de l'éclairement et de la température (coefficient négatif : R diminue quand la grandeur augmente). En pont diviseur avec une résistance fixe R, la tension au point milieu vaut Vcc × R / (R + R_capteur). analogRead la numérise ; on étalonne ensuite valeur ↔ grandeur (réponse souvent non linéaire pour la NTC).",
    expert: "La NTC suit R(T) = R0·exp(B·(1/T − 1/T0)) (modèle β), franchement non linéaire ; on linéarise par table ou Steinhart-Hart à trois coefficients. La résistance fixe règle la sensibilité autour du point de fonctionnement (idéalement R ≈ R_capteur au point d'intérêt). La LDR a une réponse logarithmique et dispersée : on calibre pour mesurer, on se contente d'un seuil sinon." },
  a8: { simple: "Un interrupteur ne fait que « tout » ou « rien ». Pour un « à moitié », on l'actionne très vite : allumé la moitié du temps, éteint l'autre moitié. Trop rapide pour l'œil, qui voit une lumière moyenne. analogWrite règle cette proportion de 0 (éteint) à 255 (plein).",
    technique: "La PWM génère un signal carré à fréquence fixe (~490 Hz, ~980 Hz sur les broches 5/6 de l'Uno) dont on règle le rapport cyclique : analogWrite(pin, d) impose un duty = d/255. La valeur moyenne vaut d/255 × Vcc ; un filtre passe-bas (ou l'inertie d'un moteur, la persistance rétinienne) la restitue. Seules les broches d'un timer (3,5,6,9,10,11) la portent.",
    expert: "Les sorties PWM dérivent des comparateurs des Timer0/1/2 (Fast PWM ou Phase-Correct). Conséquences : analogWrite sur 5/6 (Timer0) perturbe millis()/delay() ; tone() (Timer2) bloque la PWM des broches 3/11. Résolution 8 bits ; pour plus (16 bits) on programme les timers (ICRn comme TOP). L'ondulation résiduelle dépend de la fréquence PWM et du filtre." },
  a9: { simple: "Tu as un nombre dans une échelle (0 à 1023) et tu le veux dans une autre (0 à 255). map() fait la conversion proportionnelle pour toi, comme une règle de trois. Et si tu veux juste « réagir quand ça dépasse », tu compares à un seuil avec if.",
    technique: "map(v, inLo, inHi, outLo, outHi) calcule (v − inLo)·(outHi − outLo)/(inHi − inLo) + outLo en arithmétique ENTIÈRE (troncature). Elle n'écrête pas : on chaîne constrain(v, lo, hi) pour rester dans la plage. Pour une décision binaire, un seuil (avec hystérésis si le signal est bruité) vaut mieux qu'une conversion.",
    expert: "map() étant entière, elle perd de la précision (division tronquée) ; pour des conversions fines on calcule en flottant ou on multiplie avant de diviser. Les plages peuvent être inversées (map(v,0,1023,255,0)) ou négatives. Pour des seuils robustes, on implémente un trigger de Schmitt logiciel (deux seuils) plutôt qu'une comparaison simple qui « hache » autour du point de bascule." },
  a10: { simple: "Un buzzer, c'est un petit haut-parleur : pour qu'il chante, il faut le faire vibrer plus ou moins vite. Vite = son aigu, lentement = son grave. tone(broche, fréquence) s'occupe de tout : tu donnes la « vitesse de vibration » (la fréquence) et il joue la note. noTone l'arrête.",
    technique: "tone(pin, freq[, durée]) génère un signal carré à la fréquence demandée (≈ 31 Hz à 65 kHz) ; la hauteur perçue suit la fréquence. Sans durée, le son persiste jusqu'à noTone(pin). Une seule note à la fois (la fonction monopolise un timer). Les notes sont des fréquences précises (la3 = 440 Hz, octave = ×2).",
    expert: "tone() s'appuie sur le Timer2 (sur l'Uno) en mode CTC et bascule la broche par interruption : conflit avec la PWM des broches 3 et 11, une seule voie à la fois. Pour de la polyphonie ou un son de qualité (formes d'onde, enveloppes), on passe à un DAC/PWM filtré, à une bibliothèque dédiée ou à un module audio ; un piézo seul ne rend qu'un carré, riche en harmoniques." },
  a11: { simple: "Une variable, c'est une boîte étiquetée où tu ranges un nombre pour le retrouver plus tard. Tu écris dessus son nom et ce qu'elle contient : int score = 0; crée la boîte « score » avec 0 dedans. Ensuite tu peux changer son contenu quand tu veux.",
    technique: "Une variable associe un nom, un type (qui fixe la taille et l'interprétation) et une valeur. Sur AVR : int 16 bits signé, long 32, float 32 (simple précision), bool/byte 8. La portée dépend du lieu de déclaration : globale (persistante, en SRAM) ou locale (pile, recréée à chaque appel). Initialiser évite les valeurs indéterminées.",
    expert: "Le choix du type est un compromis taille/plage/vitesse : sur un cœur 8 bits, l'arithmétique 16/32 bits coûte plusieurs instructions et le float (pas de FPU) est émulé, donc lent. Gare aux dépassements silencieux (un int qui passe 32767 repart à −32768) et aux conversions implicites. Les globales consomment de la SRAM en permanence ; const, #define et PROGMEM (Flash) soulagent la RAM." },
  a12: { simple: "Décider, c'est « si… alors… sinon… ». if (il fait sombre) { allume } else { éteins }. La machine regarde si la condition est vraie : si oui elle fait le premier bloc, sinon le second. Tu compares des valeurs avec des signes comme > (plus grand) ou == (égal).",
    technique: "if (expr) exécute son bloc si expr est non nulle (vraie). Les comparaisons (==, !=, <, >, <=, >=) renvoient un booléen ; on les combine par && (ET), || (OU), ! (NON), avec évaluation en court-circuit. else et else if chaînent les cas. Erreur fréquente : = (affectation) au lieu de == (test d'égalité).",
    expert: "Le court-circuit de && et || évite d'évaluer le second opérande quand le premier suffit (utile, parfois nécessaire : if (p != NULL && p->x)). Toute valeur non nulle est « vraie », d'où le piège de if (x = 5). Pour de nombreux cas discrets, switch/case est plus lisible. Les comparaisons signé/non signé et l'égalité de float réservent des surprises." },
  a13: { simple: "Plutôt qu'écrire dix fois la même ligne, on dit « répète ça dix fois » : c'est la boucle for. Une variable compte les tours (0, 1, 2…). La boucle while, elle, répète « tant que » quelque chose reste vrai — par exemple tant qu'un bouton n'est pas pressé.",
    technique: "for (init; test; pas) : init une fois, test évalué avant chaque itération (sortie si faux), pas après chaque itération. while (test) équivaut à un for sans init ni pas. do { } while (test) garantit au moins un passage. break sort de la boucle, continue saute au tour suivant.",
    expert: "La variable d'indice doit être assez large pour la borne (un uint8_t bouclant jusqu'à 256 ne sort jamais). Dans loop(), une boucle longue ou un while bloquant nuit à la réactivité (même effet que delay) : on préfère souvent une machine à états cadencée par millis(). Attention aux conditions de bord (off-by-one) et aux boucles infinies involontaires." },
  a14: { simple: "Avec delay, la carte « dort » et ne peut rien faire d'autre. millis(), c'est une horloge qu'on regarde sans s'arrêter : « ça fait combien de temps ? ». On note l'heure de la dernière fois, et dès qu'il s'est écoulé assez de temps, on agit — tout en continuant à surveiller le reste.",
    technique: "millis() renvoie le temps depuis le boot en millisecondes (unsigned long, ~49,7 jours avant repli). Motif non bloquant : static unsigned long last; if (millis() - last >= INTERVAL) { last += INTERVAL; action(); }. La soustraction en non signé gère le débordement. micros() offre la microseconde (repli ~71 min).",
    expert: "Stocker last et l'intervalle en unsigned long et soustraire AVANT de comparer (millis() - last >= T) immunise au rollover, contrairement à millis() >= last + T. Incrémenter last += T (plutôt que last = millis()) évite la dérive cumulative mais peut « rattraper » après une itération trop longue. Pour plusieurs tâches, on généralise en ordonnanceur coopératif (table {période, dernier, fonction})." },
  a15: { simple: "Quand tu appuies, le contact « tremble » une fraction de seconde avant de se stabiliser. Pour la carte, ça ressemble à plusieurs appuis très rapides. La solution : ne réagir qu'au moment du changement, et ignorer les tremblements en attendant un petit instant que ça se calme.",
    technique: "Le rebond (bounce) produit plusieurs fronts en quelques millisecondes. Anti-rebond logiciel : mémoriser l'état précédent (détection de front : reading != lastReading) et n'accepter un changement que si millis() - lastChange > debounceDelay (~20–50 ms). Variante : plusieurs lectures concordantes. Matériel : condensateur (RC), parfois suivi d'un trigger de Schmitt.",
    expert: "La machine à états classique distingue lastReading (lecture instantanée) et buttonState (état stable validé) : on ré-arme un chronomètre à chaque variation de lastReading et on ne met à jour buttonState qu'au-delà du délai. Un APPUI = transition stable HIGH→LOW (pull-up). À cadence élevée, on combine RC + Schmitt et/ou interruption sur front filtrée, en dimensionnant RC selon le temps de rebond du contact." },
  a16: { simple: "Pour comprendre ce que fait ta carte, fais-la « parler » clairement : au lieu d'afficher 23 tout seul, affiche « temperature = 23 ». Tu écris l'étiquette avec print (qui reste sur la ligne), puis la valeur avec println (qui passe à la ligne).",
    technique: "Serial.print() émet sans saut de ligne, println() avec : on compose une ligne par appels successifs (libellé + valeur + unité). Pour les flottants, Serial.print(x) affiche par défaut deux décimales. Arduino sait aussi afficher un entier dans une autre base — Serial.print(valeur, HEX) (ou BIN, OCT) — utile pour lire des registres ou des masques de bits (le moniteur du simulateur, lui, affiche en décimal).",
    expert: "L'affichage périodique se cadence avec millis() (chapitre 3) pour ne pas saturer l'UART (~1 ms/caractère à 9600 bauds). Pour des données exploitables (traceur série, tableur), on adopte un format régulier (valeurs séparées par des virgules/tabulations, une ligne par échantillon). Le formatage de bases (HEX/BIN) et la précision des flottants (Serial.print(x, 4)) aident à inspecter finement les valeurs." },
  a17: { simple: "Une LED RGB, c'est trois petites lampes — une rouge, une verte, une bleue — collées ensemble. En réglant leur intensité, tu mélanges leurs lumières comme de la peinture lumineuse : rouge + vert donne du jaune, les trois ensemble donnent du blanc. Chaque couleur se règle de 0 à 255.",
    technique: "Trois canaux PWM (un par couleur primaire) commandent l'intensité (0–255). La couleur résulte de la synthèse additive (RVB), comme sur un écran. Selon le modèle (anode ou cathode commune), 255 correspond au maximum ou au minimum d'intensité (cathode commune : valeur haute = plus lumineux ; anode commune : l'inverse). Une résistance par canal limite le courant.",
    expert: "La perception n'est pas linéaire (gamma) : un dégradé linéaire en valeur PWM paraît irrégulier ; on applique une correction gamma (table de 256 valeurs) pour un fondu visuellement uniforme. Le mélange additif en PWM reste approximatif (pas de gestion colorimétrique, dépendance aux LED) ; pour de la couleur précise on calibre ou on passe à des LED adressables (WS2812) pilotées par un protocole dédié." },
  a18: { simple: "Réagir à un seuil, c'est « si c'est plus bas que tant, fais ça ». Mais si la mesure tremble juste autour de la limite, la sortie clignote sans arrêt. L'astuce : deux limites au lieu d'une — une pour allumer, une (un peu plus haute) pour éteindre. Entre les deux, on ne change rien.",
    technique: "Un seuil simple compare la mesure à une constante. Si le signal est bruité ou varie lentement près du seuil, la sortie oscille (chattering). L'hystérésis introduit deux seuils (bas/haut) et mémorise l'état : on ne bascule qu'en franchissant le seuil opposé. La largeur (haut − bas) règle l'immunité au bruit.",
    expert: "C'est un trigger de Schmitt logiciel : la décision dépend de l'état courant, pas seulement de l'entrée instantanée (système à mémoire). On dimensionne la largeur d'hystérésis au-delà de l'amplitude du bruit. Compléments : filtrage (moyenne glissante, passe-bas) en amont, ou temporisation (la condition doit tenir N ms). En matériel, un comparateur à réaction positive réalise la même fonction." },
  a19: { simple: "Voici la recette de presque tous les montages : on lit un capteur, on transforme le nombre, on commande quelque chose. Exemple : tu tournes un bouton (potentiomètre), la LED brille plus ou moins fort. Lire → convertir → agir.",
    technique: "Chaîne d'acquisition-commande : analogRead numérise l'entrée (0–1023), map() la met à l'échelle de l'actionneur (0–255 pour la PWM), analogWrite applique la commande. On insère au besoin un filtrage ou un seuil entre mesure et action. Le potentiomètre→LED est l'exemple d'école ; la structure se généralise à tout capteur/actionneur.",
    expert: "C'est une boucle ouverte (pas de retour) : la commande ne dépend que de la consigne lue. Points d'attention : bruit du CAN (filtrage/moyenne), non-linéarités (capteur, perception → correction), résolution (1023 vers 255 perd des paliers), et le timing (commande rafraîchie dans loop sans bloquer). Ajouter un capteur de sortie ferme la boucle (régulation) : c'est l'asservissement." },
  a20: { simple: "On fabrique une veilleuse intelligente : elle s'allume quand il fait sombre. La photorésistance « voit » la lumière, le programme compare à une limite, et il allume la LED si besoin. Avec une petite astuce (deux limites) pour qu'elle ne clignote pas entre chien et loup.",
    technique: "Projet de synthèse : acquisition (LDR en pont diviseur → analogRead), décision (seuil avec hystérésis pour la stabilité), action (LED, éventuellement en PWM pour un allumage doux), instrumentation (affichage série pour calibrer le seuil). Boucle non bloquante (millis()) recommandée si on ajoute d'autres tâches.",
    expert: "Améliorations naturelles : lissage de la mesure (moyenne glissante), allumage progressif (rampe PWM), calibration automatique (min/max observés), LED RGB pour varier l'ambiance, multitâche par ordonnanceur millis(). Le même squelette mesure→décision→action structure thermostat, détecteur, alarme — on ne change que capteur, critère et actionneur." },
  a21: { simple: "Un servomoteur, c'est un petit moteur qui se place à un angle précis et le tient (de 0° à 180°). Tu ne lui donnes pas une vitesse mais une position : « va à 90° », et il y va. On lui parle avec la bibliothèque Servo : on le rattache à une broche, puis on écrit l'angle voulu.",
    technique: "Le servo est piloté par un signal ~50 Hz dont la largeur d'impulsion code la consigne d'angle (≈ 1 ms → 0°, ≈ 1,5 ms → 90°, ≈ 2 ms → 180°). La bibliothèque Servo génère ce signal : Servo s; s.attach(pin); s.write(angle). write() accepte 0–180 ; writeMicroseconds() donne un contrôle fin ; read() renvoie le dernier angle. attach() occupe un timer (jusqu'à ~12 servos sur l'Uno).",
    expert: "La plage réelle dépend du modèle (souvent ~544–2400 µs, qui ne correspond pas pile à 0–180°) ; attach(pin, min, max) recalibre les bornes en µs. Côté Arduino il n'y a pas d'asservissement : le servo se déplace à sa propre vitesse vers la cible. Plusieurs servos ou un servo en charge exigent une alimentation externe (les pics de courant font chuter le 5 V de la carte et redémarrent le µC), masse commune obligatoire. Pour un mouvement lent et maîtrisé, on rampe l'angle pas à pas avec des delay." },
  a22: { simple: "Le capteur ultrason fonctionne comme une chauve-souris : il envoie un « bip » que l'oreille n'entend pas et écoute l'écho qui revient quand l'onde rebondit sur un objet. Plus l'objet est loin, plus l'écho met de temps à revenir : en mesurant ce temps, on connaît la distance.",
    technique: "Avec le HC-SR04 : impulsion de 10 µs sur Trig → le capteur émet une salve puis met Echo à HIGH pendant le temps d'aller-retour. pulseIn(echo, HIGH) mesure cette durée en µs. Le son parcourant ~0,0343 cm/µs et l'onde faisant l'aller-retour, distance_cm = durée / 58 (soit durée × 0,0343 / 2).",
    expert: "Limites : portée ~2–400 cm, cône d'émission ~15° ; les surfaces molles, inclinées ou petites diffusent l'écho (mesures erratiques ou absence d'écho). La vitesse du son dépend de la température (≈ 331 + 0,6·T m/s), d'où une dérive de quelques % à compenser si la précision compte. On ajoute un timeout à pulseIn pour ne pas bloquer si aucun écho ne revient, et on filtre (médiane de plusieurs mesures) pour rejeter les aberrations." },
};
const WHY_A = {
  a1: "Pourquoi deux fonctions et pas une ? Parce qu'on sépare ce qui se règle une fois (le décor : broches, vitesse série) de ce qui doit se répéter (l'action). Tout mélanger obligerait à re-régler les broches à chaque tour — inutile et source d'erreurs.",
  a2: "Pourquoi régler pinMode AVANT d'écrire ? Parce qu'au démarrage toutes les broches sont en entrée par défaut. digitalWrite sur une entrée n'impose aucune tension (au mieux un pull-up) : la LED ne s'allumerait pas. On déclare donc la sortie d'abord.",
  a3: "Pourquoi delay() pose-t-il problème ? Parce qu'il gèle tout le programme : pendant un delay(1000) tu ne peux pas détecter un appui sur un bouton. Pour un simple clignotant c'est sans conséquence ; pour rester réactif, on mesure le temps avec millis() sans bloquer.",
  a4: "Pourquoi la logique est-elle inversée avec INPUT_PULLUP ? Parce que la résistance interne tire la broche vers 5 V (HIGH) tant qu'on n'appuie pas. Le bouton relie la broche à la masse (0 V) quand on l'enfonce. Donc repos = HIGH, appui = LOW : on teste == LOW.",
  a5: "Pourquoi 9600 ? C'est une vitesse historique, sûre et largement compatible — n'importe quelle valeur convient tant que les deux extrémités l'utilisent. Note propre au simulateur : les chaînes de caractères doivent rester en ASCII (sans accent) ; les commentaires, eux, acceptent les accents.",
  a6: "Pourquoi 1023 et pas 1024 ? Parce que sur 10 bits il y a 1024 valeurs possibles, numérotées de 0 à 1023 : la plus grande est donc 1023 (comme 8 bits donnent 0 à 255). 0 V donne 0, et la pleine échelle (5 V) donne 1023.",
  a7: "Pourquoi un pont diviseur et pas la résistance seule ? Parce que analogRead mesure une TENSION, pas une résistance. Le pont (capteur + résistance fixe entre 5 V et la masse) convertit la résistance variable en une tension variable au point milieu — c'est elle qu'on lit.",
  a8: "Pourquoi seulement certaines broches (~) ? Parce que la PWM est produite par les minuteries (timers) matérielles, et seules les broches câblées sur la sortie d'un comparateur de timer peuvent l'émettre. Les autres ne savent faire que 0 ou 5 V.",
  a9: "Pourquoi map() peut-elle sortir de la plage voulue ? Parce qu'elle applique une simple proportion, sans garde-fou : une entrée de 1100 (au-delà de 1023) donnera une sortie au-delà de 255. D'où l'usage de constrain() pour forcer le résultat à rester entre les bornes.",
  a10: "Pourquoi la fréquence donne-t-elle la hauteur de la note ? Parce que l'oreille perçoit la rapidité des vibrations comme une hauteur : plus la fréquence est élevée (vibrations rapprochées), plus le son est aigu. 440 Hz = 440 allers-retours par seconde = le la de référence.",
  a11: "Pourquoi déclarer la variable hors de loop() pour compter ? Parce qu'une variable créée DANS loop() est remise à sa valeur initiale à chaque tour : ton compteur resterait bloqué. Déclarée globalement (avant setup), elle vit pendant tout le programme et se souvient d'un tour à l'autre.",
  a12: "Pourquoi != n'est-il pas la même chose que = ? Parce que = AFFECTE (range une valeur), tandis que == et != COMPARENT (testent). if (x = 5) exécute toujours son bloc (5 est « vrai ») et écrase x ; if (x == 5) teste si x vaut 5 sans le modifier. Une lettre de différence, un comportement opposé.",
  a13: "Pourquoi le for compte-t-il de 0 à 9 et pas à 10 pour « dix fois » ? Parce que la condition i < 10 arrête la boucle dès que i atteint 10 : on exécute donc pour i = 0, 1, …, 9, soit exactement dix tours. Compter à partir de 0 est la convention en programmation.",
  a14: "Pourquoi soustraire (millis() - dernier) plutôt que comparer à (dernier + intervalle) ? Parce que millis() revient à zéro après ~49 jours. La soustraction en entier non signé donne quand même le bon écart au moment du repli, alors que dernier + intervalle peut déborder et fausser le test. Le motif par soustraction est robuste.",
  a15: "Pourquoi un seul appui peut-il être compté plusieurs fois ? Parce que le contact métallique du bouton rebondit physiquement quelques millisecondes : il établit et coupe le circuit plusieurs fois de suite. La carte, très rapide, voit ces oscillations comme autant d'appuis. L'anti-rebond les filtre.",
  a16: "Pourquoi distinguer print et println ? Parce que print laisse le curseur en place — on peut donc coller plusieurs morceaux sur une même ligne (« temp = » puis 23 puis « C ») — tandis que println termine la ligne. En combinant les deux, on compose des messages lisibles plutôt qu'une colonne de nombres nus.",
  a17: "Pourquoi parle-t-on de synthèse additive (et pas comme avec de la peinture) ? Parce qu'on additionne des LUMIÈRES, pas des pigments. En lumière, rouge + vert + bleu donnent du blanc (toutes les couleurs réunies), alors qu'en peinture tout mélanger tend vers le noir (synthèse soustractive). Écrans et LED RGB fonctionnent en additif.",
  a18: "Pourquoi deux seuils valent-ils mieux qu'un ? Parce qu'avec un seul seuil, une mesure qui oscille de quelques unités autour de la limite fait basculer la sortie en permanence. Deux seuils créent une « zone morte » : une fois allumé, il faut remonter franchement (au-dessus du seuil haut) pour éteindre. Le bruit ne suffit plus à faire basculer.",
  a19: "Pourquoi passer par map() entre le potentiomètre et la LED ? Parce que le potentiomètre se lit sur 0–1023 (10 bits) mais analogWrite attend 0–255 (8 bits). map(v, 0, 1023, 0, 255) fait la mise à l'échelle proportionnelle : sans elle, on enverrait des valeurs hors plage à la LED.",
  a20: "Pourquoi ajouter une hystérésis à la veilleuse ? Parce qu'au crépuscule, la lumière varie lentement autour du seuil : avec un seul seuil, la LED clignoterait sans arrêt pendant de longues minutes. Deux seuils (allumer plus bas, éteindre plus haut) créent une zone morte qui rend l'allumage net et stable.",
  a21: "Pourquoi parle-t-on d'un angle et pas d'une vitesse ? Parce qu'un servomoteur intègre son propre asservissement : un capteur de position et une électronique qui amènent l'axe à l'angle demandé et l'y maintiennent. Le signal que tu envoies (la largeur d'impulsion) est une CONSIGNE de position ; c'est le servo, pas l'Arduino, qui se charge d'y aller et d'y rester. C'est ce qui le distingue d'un moteur « normal » qu'on commande en vitesse.",
  a22: "Pourquoi diviser la durée par 58 ? Le son se déplace à environ 340 m/s, soit 0,0343 cm par microseconde. Mais l'onde fait l'aller ET le retour : la distance réelle vaut donc (durée × 0,0343) / 2. Or 1 / (0,0343 / 2) ≈ 58, donc distance_cm ≈ durée_µs / 58. Le « 58 » encapsule à la fois la vitesse du son et le facteur 2 de l'aller-retour.",
};
const EXERCISES_A = {
  a1: { intro: "On apprend à lire un sketch : qui tourne une fois, qui tourne en boucle, et où ranger chaque ligne.",
    ex: [{ t: "Exemple", p: "Que fait ce sketch : void setup(){} void loop(){} ?", s: "Rien de visible. setup() ne fait rien au démarrage, loop() ne fait rien mais tourne quand même en boucle. C'est le sketch valide le plus court." }],
    q: [{ l: "Découverte", p: "Laquelle des deux fonctions s'exécute plusieurs fois ?", s: "loop() — elle est répétée sans fin. setup() ne passe qu'une fois." },
      { l: "Échauffement", p: "Où mettrais-tu une instruction qui ne doit s'exécuter qu'une seule fois au démarrage ?", s: "Dans setup()." },
      { l: "Application", p: "Un sketch écrit void loop() sans accolades. Est-il valide ?", s: "Non : il manque le corps { }. Il faut au minimum void loop() { }." },
      { l: "Défi", p: "À peu près combien de fois loop() s'exécute-t-elle en une seconde si elle ne contient qu'une instruction très courte ?", s: "Des dizaines à des centaines de milliers de fois : le microcontrôleur tourne à 16 MHz. C'est pourquoi on ajoute des delay() pour ralentir à l'échelle humaine." },
      { l: "Examen", p: "Explique en une phrase la différence entre setup() et loop() à quelqu'un qui débute.", s: "setup() prépare le décor une fois au réveil ; loop() joue la scène en boucle tant que la carte est alimentée." }] },
  a2: { intro: "On manipule une sortie numérique : la déclarer, l'allumer, l'éteindre, et comprendre la broche 13.",
    ex: [{ t: "Exemple", p: "Écris les deux lignes pour allumer en continu la LED de la carte.", s: "Dans setup() : pinMode(13, OUTPUT); — dans loop() : digitalWrite(13, HIGH); La LED « L » reste allumée." }],
    q: [{ l: "Découverte", p: "Quelle valeur passe la broche à ≈ 5 V : HIGH ou LOW ?", s: "HIGH (état haut ≈ 5 V). LOW = 0 V." },
      { l: "Échauffement", p: "Dans quelle fonction met-on pinMode(13, OUTPUT) ?", s: "Dans setup() : on règle le rôle de la broche une seule fois." },
      { l: "Application", p: "On écrit digitalWrite(8, HIGH) mais on a oublié pinMode(8, OUTPUT). Que se passe-t-il ?", s: "La broche 8 est restée en entrée : aucune tension imposée, la LED branchée dessus ne s'allume pas (digitalWrite n'active au plus qu'un pull-up faible)." },
      { l: "Défi", p: "Quelle broche porte la LED intégrée de l'Uno, et comment l'écrire de façon lisible ?", s: "La broche 13. On peut écrire LED_BUILTIN à la place de 13 : pinMode(LED_BUILTIN, OUTPUT)." },
      { l: "Examen", p: "Pourquoi branche-t-on une résistance en série avec une LED ?", s: "Pour limiter le courant : sans elle la LED tirerait trop (au-delà de ~20 mA) et la broche comme la LED pourraient être endommagées. La résistance fixe le courant à une valeur sûre." }] },
  a3: { intro: "On joue avec le temps : durées, rythme de clignotement, et la limite du delay() bloquant.",
    ex: [{ t: "Exemple", p: "Durée d'un clignotement complet avec delay(500) allumé puis delay(500) éteint ?", s: "500 + 500 = 1000 ms = 1 seconde, soit une fréquence de 1 Hz (un clignotement par seconde)." }],
    q: [{ l: "Découverte", p: "delay(2000) attend combien de temps ?", s: "2000 ms = 2 secondes." },
      { l: "Échauffement", p: "Tu veux une LED allumée 200 ms puis éteinte 800 ms. Quels deux delay ?", s: "delay(200) après digitalWrite(HIGH), puis delay(800) après digitalWrite(LOW)." },
      { l: "Application", p: "Pour clignoter deux fois plus vite qu'avec 500/500, quels délais utiliser ?", s: "250 ms / 250 ms : la période passe de 1000 ms à 500 ms, soit 2 Hz." },
      { l: "Défi", p: "Pendant un delay(1000), peux-tu détecter l'appui d'un bouton ? Pourquoi ?", s: "Non : delay() est bloquant, le programme est figé pendant toute la seconde. L'appui pourrait survenir et repartir sans être vu." },
      { l: "Examen", p: "Donne le motif complet (4 lignes) qui fait clignoter la broche 13 à 1 Hz dans loop().", s: "digitalWrite(13, HIGH); delay(500); digitalWrite(13, LOW); delay(500); — la broche doit avoir été mise en OUTPUT dans setup()." }] },
  a4: { intro: "On lit une entrée proprement : éviter le flottement, comprendre le pull-up et la logique inversée.",
    ex: [{ t: "Exemple", p: "Avec pinMode(2, INPUT_PULLUP) et un bouton entre la broche 2 et la masse, que renvoie digitalRead(2) au repos ?", s: "HIGH (1) : le pull-up interne tire la broche à 5 V au repos. À l'appui, elle tombe à LOW (0)." }],
    q: [{ l: "Découverte", p: "digitalRead renvoie une tension en volts, ou HIGH/LOW ?", s: "HIGH ou LOW (1 ou 0). Elle interprète la tension par rapport à un seuil, elle ne la mesure pas." },
      { l: "Échauffement", p: "Pourquoi ne pas laisser une entrée « en l'air » ?", s: "Elle flotte : elle capte du bruit et renvoie des 0 et des 1 au hasard. Il faut une résistance de tirage." },
      { l: "Application", p: "Avec INPUT_PULLUP, quel test détecte un appui : == HIGH ou == LOW ?", s: "== LOW : au repos la broche est à HIGH, l'appui la met à LOW." },
      { l: "Défi", p: "Tu appuies une fois mais le programme compte parfois 2 ou 3 appuis. Quel phénomène, et une parade ?", s: "Le rebond (bounce) : le contact mécanique oscille quelques millisecondes. Parade : anti-rebond logiciel (ignorer les changements pendant ~20–50 ms via millis) ou matériel (RC)." },
      { l: "Examen", p: "Décris le câblage et le test pour allumer la LED 13 tant qu'un bouton est pressé (pull-up).", s: "Bouton entre broche 2 et masse ; pinMode(2, INPUT_PULLUP) et pinMode(13, OUTPUT). Dans loop : digitalWrite(13, digitalRead(2) == LOW ? HIGH : LOW); — pressé (LOW) → LED allumée." }] },
  a5: { intro: "On fait parler la carte : ouvrir la liaison, afficher texte et valeurs, s'en servir pour déboguer.",
    ex: [{ t: "Exemple", p: "Affiche une fois le mot Bonjour au démarrage.", s: "Dans setup() : Serial.begin(9600); puis Serial.println(\"Bonjour\"); — le mot apparaît une fois dans le moniteur." }],
    q: [{ l: "Découverte", p: "Dans quelle fonction met-on Serial.begin(9600) ?", s: "Dans setup() : on ouvre la liaison une seule fois." },
      { l: "Échauffement", p: "Quelle différence entre Serial.print et Serial.println ?", s: "println ajoute un retour à la ligne après l'affichage ; print laisse le curseur sur la même ligne." },
      { l: "Application", p: "Comment afficher la valeur lue sur A0 ?", s: "Serial.println(analogRead(A0)); — la valeur (0 à 1023) s'affiche, suivie d'un retour ligne." },
      { l: "Défi", p: "Pourquoi afficher des milliers de lignes par seconde dans loop() peut-il ralentir le programme ?", s: "Parce que l'envoi série prend du temps (~1 ms par caractère à 9600 bauds) : loop() attend la transmission. On espace donc les affichages." },
      { l: "Examen", p: "Tu veux suivre l'état d'un bouton (pull-up) dans le moniteur. Donne les lignes clés.", s: "setup : Serial.begin(9600); pinMode(2, INPUT_PULLUP); — loop : Serial.println(digitalRead(2) == LOW ? \"appuye\" : \"relache\"); (texte en ASCII, sans accent)." }] },
  a6: { intro: "On apprivoise le CAN : ce que renvoie analogRead, comment repasser en volts, et l'ordre de grandeur d'un pas.",
    ex: [{ t: "Exemple", p: "analogRead renvoie 512. À quelle tension cela correspond-il (référence 5 V) ?", s: "U ≈ 512 × 5 ÷ 1023 ≈ 2,50 V. 512 est à peu près la moitié de 1023, donc la moitié de 5 V." }],
    q: [{ l: "Découverte", p: "Quelle est la plus grande valeur que peut renvoyer analogRead sur l'Uno ?", s: "1023 (le CAN est sur 10 bits : 1024 valeurs, de 0 à 1023)." },
      { l: "Échauffement", p: "Sur quelles broches utilise-t-on analogRead ?", s: "Les broches analogiques A0 à A5 (sur l'Uno)." },
      { l: "Application", p: "analogRead renvoie 0. Que vaut la tension lue ?", s: "0 V : la valeur 0 correspond à l'absence de tension (par rapport à la masse)." },
      { l: "Défi", p: "Quelle tension correspond à la valeur 100 (référence 5 V) ?", s: "U ≈ 100 × 5 ÷ 1023 ≈ 0,49 V." },
      { l: "Examen", p: "Explique pourquoi on parle de conversion « 10 bits » et ce que cela implique sur la finesse de mesure.", s: "10 bits = 2¹⁰ = 1024 niveaux. La plage 0–5 V est découpée en 1024 marches d'environ 4,9 mV : on ne distingue pas deux tensions plus proches que ce pas." }] },
  a7: { intro: "On relie capteur, pont diviseur et valeur lue : sens de variation et lecture.",
    ex: [{ t: "Exemple", p: "Pourquoi ne peut-on pas brancher une photorésistance seule sur A0 ?", s: "Parce que analogRead lit une tension, et une résistance seule entre A0 et la masse ne fixe pas de tension exploitable. Il faut un pont diviseur (résistance fixe + capteur) pour transformer la résistance variable en tension variable." }],
    q: [{ l: "Découverte", p: "La résistance d'une LDR augmente-t-elle ou diminue-t-elle quand on l'éclaire davantage ?", s: "Elle diminue : plus de lumière → moins de résistance." },
      { l: "Échauffement", p: "Que mesure réellement analogRead sur la broche d'un capteur résistif ?", s: "Une tension (0–5 V, rendue en 0–1023), pas directement la résistance." },
      { l: "Application", p: "Pour lire une thermistance avec l'Arduino, quel montage faut-il autour d'elle ?", s: "Un pont diviseur : la thermistance en série avec une résistance fixe, entre 5 V et la masse, le point milieu sur une broche analogique." },
      { l: "Défi", p: "La NTC a-t-elle une réponse linéaire entre température et valeur lue ?", s: "Non : sa résistance varie de façon exponentielle (modèle β / Steinhart-Hart). On linéarise par calcul ou par table pour obtenir des degrés." },
      { l: "Examen", p: "Décris la chaîne complète qui permet d'allumer une LED quand il fait sombre.", s: "LDR en pont diviseur → broche analogique ; dans loop : lire analogRead, comparer à un seuil, et si la valeur indique l'obscurité, mettre la LED à HIGH (sinon LOW)." }] },
  a8: { intro: "On dose une sortie sans vrai analogique : rapport cyclique, broches PWM, fondu.",
    ex: [{ t: "Exemple", p: "Quelle valeur passer à analogWrite pour une LED à environ la moitié de sa luminosité ?", s: "≈ 127 (la moitié de 255). Le rapport cyclique vaut alors ≈ 50 % : la LED est allumée la moitié du temps." }],
    q: [{ l: "Découverte", p: "Quelle plage de valeurs accepte analogWrite : 0–1023 ou 0–255 ?", s: "0 à 255 (8 bits). À ne pas confondre avec analogRead, qui rend 0–1023." },
      { l: "Échauffement", p: "Que fait analogWrite(9, 255) ?", s: "La broche 9 est au rapport cyclique maximal : équivalent à toujours HIGH (LED au maximum)." },
      { l: "Application", p: "Pourquoi analogWrite(7, 127) ne fait-il pas varier la luminosité ?", s: "La broche 7 n'est pas une broche PWM (pas de ~). Hors broches PWM, analogWrite se comporte en tout-ou-rien (HIGH si valeur ≥ 128, LOW sinon)." },
      { l: "Défi", p: "Comment obtenir un fondu (LED qui « respire ») ?", s: "Faire croître puis décroître la valeur de 0 à 255 dans une boucle, avec un petit delay entre chaque pas, en l'envoyant à analogWrite sur une broche ~." },
      { l: "Examen", p: "Explique en une phrase ce que règle vraiment analogWrite et pourquoi la LED paraît à demi-allumée.", s: "Il règle le rapport cyclique d'un signal qui clignote très vite ; l'œil en perçoit la moyenne, donc une demi-puissance pour une valeur de ≈ 127." }] },
  a9: { intro: "On change d'échelle proprement : règle de trois avec map, bornage avec constrain, décisions par seuil.",
    ex: [{ t: "Exemple", p: "Que vaut map(512, 0, 1023, 0, 255) ?", s: "≈ 127 : 512 est à mi-plage de [0,1023], donc on tombe à mi-plage de [0,255]. (Calcul entier : 512 × 255 ÷ 1023 = 127.)" }],
    q: [{ l: "Découverte", p: "À quoi sert map() en une phrase ?", s: "À convertir un nombre d'une plage de valeurs vers une autre, proportionnellement (une règle de trois)." },
      { l: "Échauffement", p: "Écris l'appel qui transforme une lecture A0 (0–1023) en niveau PWM (0–255).", s: "map(analogRead(A0), 0, 1023, 0, 255)." },
      { l: "Application", p: "map() garantit-elle que le résultat reste dans la plage de sortie ?", s: "Non : elle ne borne pas. Pour cela on ajoute constrain(résultat, min, max)." },
      { l: "Défi", p: "Que valent map(0, 0, 1023, 0, 180) et map(1023, 0, 1023, 0, 180) ?", s: "0 et 180 : les extrémités d'une plage tombent sur les extrémités de l'autre." },
      { l: "Examen", p: "Pour allumer une LED seulement quand un capteur dépasse la moitié de l'échelle, vaut-il mieux map() ou un seuil ? Justifie.", s: "Un seuil : la décision est tout-ou-rien — if (analogRead(A0) > 511) LED HIGH; else LOW. map() servirait à DOSER (PWM), pas pour un simple oui/non." }] },
  a10: { intro: "On fait sonner le buzzer : fréquence et hauteur, démarrer/arrêter, enchaîner une mélodie.",
    ex: [{ t: "Exemple", p: "Quelle ligne joue un la (440 Hz) sur un buzzer en broche 8 ?", s: "tone(8, 440); — le buzzer émet un la jusqu'à un noTone(8)." }],
    q: [{ l: "Découverte", p: "Qu'est-ce qui détermine si le son est aigu ou grave ?", s: "La fréquence : plus elle est haute, plus le son est aigu ; plus elle est basse, plus il est grave." },
      { l: "Échauffement", p: "Quelle fonction arrête le son du buzzer ?", s: "noTone(broche)." },
      { l: "Application", p: "Comment jouer un son de 1000 Hz pendant exactement une demi-seconde, sans noTone ?", s: "tone(broche, 1000, 500); — la durée (500 ms) coupe le son automatiquement." },
      { l: "Défi", p: "Comment enchaîner trois notes do-ré-mi (262, 294, 330 Hz) ?", s: "tone() la première note, delay() pour la laisser sonner, puis tone() la suivante, etc. (ou des tone(..., durée) successifs avec les delay correspondants)." },
      { l: "Examen", p: "Le la vaut 440 Hz. Quelle est la fréquence du la à l'octave au-dessus, et pourquoi ?", s: "880 Hz : monter d'une octave double la fréquence, donc 2 × 440 = 880 Hz." }] },
  a11: { intro: "On manipule la mémoire du programme : déclarer, typer, modifier, et comprendre la portée.",
    ex: [{ t: "Exemple", p: "Écris une variable entière nommée n valant 5 au départ.", s: "int n = 5; — un entier nommé n, initialisé à 5. On peut ensuite faire n = n + 1; pour le passer à 6." }],
    q: [{ l: "Découverte", p: "À quoi sert une variable ?", s: "À mémoriser une valeur sous un nom, pour la relire ou la modifier plus tard." },
      { l: "Échauffement", p: "Quel type choisir pour stocker un nombre à virgule ?", s: "float (un nombre à virgule, sur 32 bits)." },
      { l: "Application", p: "Quelle est la valeur de n après int n = 4; n = n + 3; ?", s: "7 (4 puis +3)." },
      { l: "Défi", p: "Sur l'Uno, un int vaut 30000 et on lui ajoute 5000. Que se passe-t-il ?", s: "Dépassement : un int (16 bits signé) plafonne à 32767 ; 35000 « déborde » et donne une valeur négative erronée. Il fallait un long." },
      { l: "Examen", p: "Pourquoi un compteur déclaré dans loop() ne compte-t-il jamais au-delà de sa valeur de départ ?", s: "Parce qu'il est recréé (réinitialisé) à chaque tour de loop. Pour compter, on le déclare en variable globale (avant setup), qui conserve sa valeur entre les tours." }] },
  a12: { intro: "On fait décider le programme : conditions, comparaisons, combinaisons, et le piège = / ==.",
    ex: [{ t: "Exemple", p: "Écris la condition « la valeur de A0 dépasse 600 ».", s: "if (analogRead(A0) > 600) { … } — le bloc s'exécute quand la lecture est strictement supérieure à 600." }],
    q: [{ l: "Découverte", p: "Que fait le bloc else ?", s: "Il s'exécute quand la condition du if est fausse (le cas « sinon »)." },
      { l: "Échauffement", p: "Quel opérateur teste l'égalité de deux valeurs ?", s: "== (double égal). = seul affecte une valeur." },
      { l: "Application", p: "Écris la condition « x vaut 1 ET y est plus petit que 10 ».", s: "if (x == 1 && y < 10)." },
      { l: "Défi", p: "Pourquoi if (x = 0) ne fait-il jamais le bloc, et if (x = 5) toujours ?", s: "= affecte : x devient 0 (valeur « fausse » → bloc ignoré) ou 5 (valeur « vraie » → bloc exécuté). Le test voulait sûrement ==." },
      { l: "Examen", p: "Écris la logique : allumer la LED 13 si A0 > 700 OU si le bouton (pull-up, broche 2) est pressé.", s: "if (analogRead(A0) > 700 || digitalRead(2) == LOW) digitalWrite(13, HIGH); else digitalWrite(13, LOW);" }] },
  a13: { intro: "On répète proprement : le for et ses trois parties, le while, et le danger de la boucle infinie.",
    ex: [{ t: "Exemple", p: "Combien de fois s'exécute le bloc de for (int i = 0; i < 5; i++) ?", s: "5 fois : i prend les valeurs 0, 1, 2, 3, 4 (la boucle s'arrête quand i atteint 5)." }],
    q: [{ l: "Découverte", p: "Quelle boucle utilise-t-on pour répéter un nombre connu de fois ?", s: "for (avec un compteur)." },
      { l: "Échauffement", p: "Quelles sont les trois parties d'un for ?", s: "L'initialisation, la condition de poursuite et l'incrément (init ; condition ; incrément)." },
      { l: "Application", p: "Quelles valeurs prend i dans for (int i = 0; i < 3; i++) ?", s: "0, 1, 2." },
      { l: "Défi", p: "Que se passe-t-il avec while (true) { } et comment en sortir volontairement ?", s: "La boucle tourne indéfiniment (condition toujours vraie) et bloque le reste du programme. On en sort avec un break (sur une condition interne)." },
      { l: "Examen", p: "Écris un for qui fait un fondu : valeur de 0 à 255 sur la broche 9, avec un petit délai.", s: "for (int v = 0; v <= 255; v++) { analogWrite(9, v); delay(5); } — la LED monte progressivement en luminosité." }] },
  a14: { intro: "On gère le temps sans figer le programme : le rôle de millis(), le motif non bloquant, le repli.",
    ex: [{ t: "Exemple", p: "Que renvoie millis() ?", s: "Le nombre de millisecondes écoulées depuis le démarrage de la carte (par ex. 5000 après 5 secondes). C'est une horloge qu'on consulte sans bloquer." }],
    q: [{ l: "Découverte", p: "millis() mesure quoi ?", s: "Le temps écoulé depuis le démarrage, en millisecondes." },
      { l: "Échauffement", p: "Quel est l'avantage de millis() sur delay() ?", s: "Il ne bloque pas : le programme continue de tourner et peut faire d'autres choses entre deux actions." },
      { l: "Application", p: "Complète : if (millis() - dernier >= 1000) { dernier = ____ ; … }", s: "millis() — on mémorise le nouvel instant de référence pour repartir d'ici." },
      { l: "Défi", p: "Pourquoi stocke-t-on dans un unsigned long l'instant retourné par millis() ?", s: "Parce que millis() renvoie un unsigned long (grand entier non signé). Un type trop petit (int) déborderait en quelques dizaines de secondes et fausserait les calculs." },
      { l: "Examen", p: "Explique le motif non bloquant pour clignoter toutes les 500 ms sans delay.", s: "On garde un instant dernier ; à chaque loop, si millis() - dernier >= 500, on met dernier = millis() et on bascule la LED. Entre-temps, loop() reste libre (par ex. pour lire un bouton)." }] },
  a15: { intro: "On fiabilise la lecture d'un bouton : comprendre le rebond, détecter le front, filtrer dans le temps.",
    ex: [{ t: "Exemple", p: "Pourquoi détecter le « front » plutôt que l'état du bouton pour compter les appuis ?", s: "Parce que tant qu'on maintient le bouton, l'état reste « pressé » : tester l'état compterait sans fin. Détecter le front (le passage relâché → pressé) ne compte qu'une fois par clic." }],
    q: [{ l: "Découverte", p: "Qu'est-ce que le rebond d'un bouton ?", s: "Les oscillations rapides du contact mécanique à l'appui/relâchement, qui créent plusieurs transitions parasites." },
      { l: "Échauffement", p: "Quel ordre de grandeur de délai utilise-t-on pour l'anti-rebond ?", s: "Environ 20 à 50 ms : assez pour couvrir le rebond, assez court pour rester imperceptible." },
      { l: "Application", p: "Pour compter les clics, regarde-t-on l'état du bouton ou son changement d'état ?", s: "Son changement (le front relâché → pressé). L'état seul resterait « pressé » pendant tout le maintien." },
      { l: "Défi", p: "Quelle fonction, avec la mémoire de l'état, sert à réaliser un anti-rebond logiciel ?", s: "millis() : on note l'instant du dernier changement et on ne valide une nouvelle transition que si le délai d'anti-rebond s'est écoulé." },
      { l: "Examen", p: "Décris en mots l'algorithme d'anti-rebond logiciel d'un bouton.", s: "Lire le bouton ; si la lecture diffère de la précédente, noter l'instant (millis). Si la lecture est restée stable plus longtemps que le délai d'anti-rebond, l'adopter comme nouvel état officiel et, si c'est une transition vers « pressé », agir." }] },
  a16: { intro: "On rend la sortie série lisible : libellés, composition d'une ligne, print contre println.",
    ex: [{ t: "Exemple", p: "Affiche « lumiere = » suivi de la valeur de A0 sur une même ligne.", s: "Serial.print(\"lumiere = \"); Serial.println(analogRead(A0)); — le libellé puis la valeur, terminés par un retour à la ligne (texte en ASCII)." }],
    q: [{ l: "Découverte", p: "Lequel termine la ligne : print ou println ?", s: "println (il ajoute un retour à la ligne). print laisse le curseur sur place." },
      { l: "Échauffement", p: "Pourquoi afficher « x = 23 » plutôt que « 23 » tout seul ?", s: "Pour savoir de quoi il s'agit : un nombre sans étiquette est ambigu, surtout avec plusieurs valeurs à l'écran." },
      { l: "Application", p: "Avec quels appels obtient-on la ligne « v = 512 » ?", s: "Serial.print(\"v = \"); Serial.println(512); — print pour le libellé, println pour la valeur et le saut de ligne." },
      { l: "Défi", p: "Pourquoi cadencer l'affichage (une ligne de temps en temps) plutôt qu'à chaque tour de loop ?", s: "Parce que l'envoi série prend du temps (~1 ms/caractère à 9600 bauds) ; afficher en continu ralentit le programme. On espace avec millis() ou un délai." },
      { l: "Examen", p: "Compose la sortie « T = 23 C » avec des print/println.", s: "Serial.print(\"T = \"); Serial.print(23); Serial.println(\" C\"); — deux print pour rester sur la ligne, un println final pour la terminer." }] },
  a17: { intro: "On compose des couleurs avec trois canaux PWM : primaires, mélanges, blanc et noir.",
    ex: [{ t: "Exemple", p: "Quelles valeurs (R, V, B) pour du jaune ?", s: "(255, 255, 0) : rouge et vert au maximum, bleu éteint. En synthèse additive, rouge + vert = jaune." }],
    q: [{ l: "Découverte", p: "Combien de LED y a-t-il dans une LED RGB ?", s: "Trois : une rouge, une verte, une bleue." },
      { l: "Échauffement", p: "Quelles valeurs (R, V, B) donnent du blanc ?", s: "(255, 255, 255) : les trois couleurs au maximum." },
      { l: "Application", p: "Quelle couleur obtient-on avec (0, 0, 255) ?", s: "Du bleu : seul le canal bleu est allumé." },
      { l: "Défi", p: "Comment obtenir du magenta (rose-violet) ?", s: "(255, 0, 255) : rouge et bleu au maximum, vert éteint (rouge + bleu = magenta)." },
      { l: "Examen", p: "Pourquoi (255,255,255) donne du blanc en RGB alors que mélanger toutes les peintures donne du noir ?", s: "Parce que la LED additionne des lumières (synthèse additive : toutes réunies = blanc), tandis que la peinture absorbe la lumière (synthèse soustractive : tout mélangé = noir)." }] },
  a18: { intro: "On déclenche une action sur une mesure : seuil simple, problème du hachage, hystérésis.",
    ex: [{ t: "Exemple", p: "Écris la condition « allumer si la lumière (A0) passe sous 300 ».", s: "if (analogRead(A0) < 300) { /* allumer */ } — la lampe s'allume quand la valeur descend sous 300 (obscurité)." }],
    q: [{ l: "Découverte", p: "Qu'appelle-t-on un « seuil » ?", s: "Une valeur limite à laquelle on compare la mesure pour décider d'agir ou non." },
      { l: "Échauffement", p: "Quel problème apparaît quand la mesure oscille juste autour du seuil ?", s: "La sortie « hache » : elle s'allume et s'éteint sans arrêt (chattering)." },
      { l: "Application", p: "Combien de seuils utilise l'hystérésis, et pourquoi ?", s: "Deux (un bas, un haut) : la zone morte entre les deux empêche la sortie de basculer sur du bruit." },
      { l: "Défi", p: "Avec seuil bas = 300 et seuil haut = 400 : à 350, la lampe allumée doit-elle s'éteindre ?", s: "Non : 350 est dans la zone morte (entre 300 et 400). On garde l'état courant ; il faut dépasser 400 pour éteindre." },
      { l: "Examen", p: "Avec quel composant électronique l'hystérésis logicielle fait-elle écho, et pourquoi ?", s: "Le trigger de Schmitt : lui aussi a deux seuils et une zone morte, ce qui immunise la sortie contre le bruit autour du point de bascule. L'hystérésis logicielle en est la transposition en code." }] },
  a19: { intro: "On assemble la chaîne mesurer → convertir → agir, et on apprend à en changer les maillons.",
    ex: [{ t: "Exemple", p: "Écris les trois lignes qui règlent la LED 9 avec le potentiomètre A0.", s: "int v = analogRead(A0); int pwm = map(v, 0, 1023, 0, 255); analogWrite(9, pwm); — lire, convertir, agir." }],
    q: [{ l: "Découverte", p: "Quelles sont les trois étapes d'un montage interactif type ?", s: "Mesurer (lire le capteur), convertir (mettre à l'échelle), agir (commander l'actionneur)." },
      { l: "Échauffement", p: "Pourquoi convertir 0–1023 en 0–255 avant analogWrite ?", s: "Parce qu'analogRead rend 0–1023 mais analogWrite attend 0–255 : map() fait la mise à l'échelle." },
      { l: "Application", p: "Quel maillon change si on remplace le potentiomètre par une photorésistance ?", s: "Le capteur (l'entrée). Le reste de la chaîne (convertir, agir) peut rester identique." },
      { l: "Défi", p: "Comment transformer la même chaîne pour piloter la FRÉQUENCE d'un buzzer au lieu de la luminosité ?", s: "On remplace l'actionneur : au lieu d'analogWrite(LED, pwm), on fait tone(buzzer, map(v, 0, 1023, 100, 2000)) — la mesure règle la fréquence." },
      { l: "Examen", p: "Décris la chaîne complète d'un montage où un potentiomètre fait varier la luminosité d'une LED.", s: "Lire le potentiomètre avec analogRead (0–1023), convertir en 0–255 avec map, puis appliquer à la LED avec analogWrite sur une broche ~. Le tout répété dans loop()." }] },
  a20: { intro: "On assemble un projet complet (veilleuse) et on identifie comment chaque chapitre y contribue.",
    ex: [{ t: "Exemple", p: "Quels sont les trois rôles à câbler/coder pour une veilleuse automatique ?", s: "Un capteur de lumière (photorésistance) pour mesurer, une LED pour éclairer, et la logique de décision (seuil) entre les deux." }],
    q: [{ l: "Découverte", p: "Quel capteur permet de détecter qu'il fait sombre ?", s: "La photorésistance (LDR) : sa valeur lue change avec la luminosité." },
      { l: "Échauffement", p: "Quand la veilleuse doit-elle allumer la LED ?", s: "Quand la luminosité passe sous le seuil (il fait sombre)." },
      { l: "Application", p: "Pourquoi afficher la valeur du capteur en série pendant la mise au point ?", s: "Pour observer les valeurs réelles (jour/nuit) et choisir un seuil pertinent." },
      { l: "Défi", p: "Sans hystérésis, que risque-t-il de se passer au crépuscule ?", s: "La LED clignote : la lumière oscille autour du seuil, donc la décision bascule sans arrêt. L'hystérésis (deux seuils) règle ça." },
      { l: "Examen", p: "Relie chaque chapitre à sa contribution dans la veilleuse.", s: "Ch.1 : allumer la LED (digitalWrite) ; ch.2 : lire la LDR (analogRead) et la PWM ; ch.3 : variables, if et millis() ; ch.4 : seuil avec hystérésis et affichage série pour fiabiliser et régler." }] },
  a21: { intro: "On apprend à commander un servomoteur en position avec la bibliothèque Servo.",
    ex: [{ t: "Exemple", p: "Quelle instruction place le servomoteur à mi-course ?", s: "s.write(90); — 90° est le milieu de la plage 0–180°." }],
    q: [{ l: "Découverte", p: "Sur un servomoteur, commande-t-on une vitesse ou une position ?", s: "Une position : un angle entre 0° et 180°. Le servo s'y rend et l'y maintient." },
      { l: "Échauffement", p: "Quelles sont les deux étapes minimales pour piloter un servo ?", s: "Le rattacher à une broche dans setup() (s.attach(broche)), puis lui donner un angle (s.write(angle))." },
      { l: "Application", p: "Tu écris s.write(200);. Que se passe-t-il ?", s: "La bibliothèque borne l'angle à 0–180 : le servo va à 180°. On reste donc toujours dans la plage 0–180°." },
      { l: "Défi", p: "Pourquoi un gros servo (ou plusieurs) ne doit-il pas être alimenté par la broche 5V de la carte ?", s: "Ses pics de courant font chuter la tension d'alimentation, ce qui peut faire redémarrer le microcontrôleur. On l'alimente par une source externe, en reliant les masses (GND commun)." },
      { l: "Examen", p: "Décris ce que fait : Servo s; s.attach(9); for(int a=0;a<=180;a+=5){ s.write(a); delay(15);}", s: "Le servo est rattaché à la broche 9, puis balaie de 0° à 180° par pas de 5°, avec 15 ms d'attente entre chaque pas : un balayage lent et régulier." }] },
  a22: { intro: "On mesure une distance en chronométrant l'écho d'une onde ultrasonore.",
    ex: [{ t: "Exemple", p: "pulseIn renvoie 1160 µs. Quelle distance, en cm ?", s: "1160 / 58 = 20 cm." }],
    q: [{ l: "Découverte", p: "Que mesure-t-on DIRECTEMENT avec un capteur ultrason ?", s: "Une durée : le temps que met l'écho à revenir (en microsecondes). La distance s'en déduit par calcul." },
      { l: "Échauffement", p: "Quelle fonction mesure la durée de l'impulsion d'écho ?", s: "pulseIn(broche, HIGH) : elle renvoie la durée (en µs) pendant laquelle la broche reste à HIGH." },
      { l: "Application", p: "Pourquoi divise-t-on la durée par 2 (facteur caché dans le /58) ?", s: "Parce que l'onde fait l'aller ET le retour : le trajet mesuré vaut deux fois la distance à l'objet." },
      { l: "Défi", p: "Le capteur ne renvoie aucun écho (objet trop loin ou absorbant). Comment éviter que le programme se fige ?", s: "On donne un délai maximal à pulseIn : pulseIn(echo, HIGH, timeout). Au-delà, elle renvoie 0 au lieu d'attendre indéfiniment." },
      { l: "Examen", p: "Donne le calcul de la distance à partir de la durée d, puis explique l'effet de la température.", s: "distance_cm = d / 58 (soit d × 0,0343 / 2). La vitesse du son augmente avec la température (~331 + 0,6·T m/s) : au chaud, garder 58 fixe sous-estime la vitesse réelle et fausse légèrement la distance." }] },
};
Object.assign(LEVELS, LEVELS_A);
Object.assign(WHY, WHY_A);
Object.assign(EXERCISES, EXERCISES_A);
const ALL_LESSONS = [...LESSONS, ...LESSONS_E, ...LESSONS_N, ...LESSONS_A];
const ALL_MISSIONS = [...MISSIONS, ...MISSIONS_E, ...MISSIONS_N, ...MISSIONS_A];
const findLesson = (id) => ALL_LESSONS.find((l) => l.id === id);
const chapOfLesson = (id) => (LESSONS_A.some((l) => l.id === id) ? "arduino" : LESSONS_E.some((l) => l.id === id) ? "electro" : LESSONS_N.some((l) => l.id === id) ? "num" : "elec");
const findMission = (id) => ALL_MISSIONS.find((m) => m.id === id);
const missionChap = (id) => (MISSIONS_A.some((m) => m.id === id) ? "arduino" : MISSIONS_N.some((m) => m.id === id) ? "num" : MISSIONS_E.some((m) => m.id === id) ? "electro" : "elec");
const chapData = (chap) => (chap === "electro"
  ? { lessons: LESSONS_E, cats: LESSON_CATS_E, missions: MISSIONS_E, chapters: CHAPTERS_E, steps: TOUR_STEPS_E, catalog: CATALOG_E, label: "Électronique" }
  : chap === "num"
  ? { lessons: LESSONS_N, cats: LESSON_CATS_N, missions: MISSIONS_N, chapters: CHAPTERS_N, steps: TOUR_STEPS_N, catalog: CATALOG_N, label: "Numérique" }
  : chap === "arduino"
  ? { lessons: LESSONS_A, cats: LESSON_CATS_A, missions: MISSIONS_A, chapters: CHAPTERS_A, steps: TOUR_STEPS_A, catalog: CATALOG_A, label: "Arduino" }
  : { lessons: LESSONS, cats: LESSON_CATS, missions: MISSIONS, chapters: CHAPTERS, steps: TOUR_STEPS, catalog: CATALOG, label: "Électricité" });

