const GLOSSARY = [
  { t: "Tension (U)", d: "Différence de potentiel entre deux points, en volts (V) ; la « poussée » qui met les charges en mouvement." },
  { t: "Courant (I)", d: "Débit de charges électriques, en ampères (A) ; I = dq/dt." },
  { t: "Résistance (R)", d: "Opposition au passage du courant, en ohms (Ω) ; R = U/I." },
  { t: "Conductance (G)", d: "Inverse de la résistance, G = 1/R, en siemens (S)." },
  { t: "Loi d'Ohm", d: "Pour un dipôle ohmique, la tension est proportionnelle au courant : U = R·I." },
  { t: "Puissance (P)", d: "Énergie échangée par seconde, en watts (W) ; P = U·I = R·I²." },
  { t: "Énergie (E)", d: "Puissance intégrée dans le temps, en joules (J) ou wattheures (Wh) ; E = P·t." },
  { t: "Effet Joule", d: "Chaleur dégagée par une résistance parcourue par un courant ; P = R·I²." },
  { t: "Dipôle", d: "Composant à deux bornes (résistance, pile, lampe…)." },
  { t: "Nœud", d: "Point de connexion d'au moins trois fils." },
  { t: "Maille", d: "Boucle fermée du circuit." },
  { t: "Loi des nœuds", d: "La somme des courants entrant dans un nœud est nulle (Kirchhoff)." },
  { t: "Loi des mailles", d: "La somme des tensions le long d'une boucle est nulle (Kirchhoff)." },
  { t: "Série", d: "Composants enchaînés sur un seul chemin : même courant, tensions qui s'additionnent." },
  { t: "Parallèle", d: "Composants partageant les deux mêmes nœuds : même tension, courants qui s'additionnent." },
  { t: "Diviseur de tension", d: "Deux résistances en série se partagent la tension : U₂ = U·R₂/(R₁+R₂)." },
  { t: "Diviseur de courant", d: "À un embranchement, le courant se partage à l'inverse des résistances." },
  { t: "Masse", d: "Point de référence choisi à 0 V pour mesurer les potentiels (symbole ⏚)." },
  { t: "Potentiel (V)", d: "« Altitude » électrique d'un point, mesurée par rapport à la masse." },
  { t: "Court-circuit", d: "Liaison de très faible résistance qui détourne le courant." },
  { t: "Circuit ouvert", d: "Coupure qui empêche le courant de circuler." },
  { t: "Source de tension", d: "Composant qui impose une tension à ses bornes (pile idéale)." },
  { t: "Résistance interne (r)", d: "Résistance propre d'une source réelle ; sous charge, U = E − r·I." },
  { t: "Thévenin", d: "Tout dipôle linéaire équivaut à une source E_th en série avec une résistance R_th." },
  { t: "Norton", d: "Équivalent : un générateur de courant I_N = E_th/R_th en parallèle avec R_th." },
  { t: "Transfert max de puissance", d: "La charge reçoit le maximum de puissance quand R = r." },
  { t: "Pont de Wheatstone", d: "Quatre résistances + voltmètre : on mesure par l'équilibre (0 V) où R₁·R₄ = R₂·R₃." },
  { t: "Fusible", d: "Élément de protection qui fond au-delà d'un courant limite." },
  { t: "Potentiomètre", d: "Résistance variable à trois bornes (rhéostat ou diviseur réglable)." },
  { t: "Va-et-vient", d: "Deux inverseurs commandant une même lampe depuis deux endroits." },
  { t: "Condensateur (C)", d: "Stocke des charges ; Q = C·U, i = C·du/dt ; bloque le continu établi." },
  { t: "Bobine / inductance (L)", d: "S'oppose aux variations de courant ; u = L·di/dt." },
  { t: "Constante de temps (τ)", d: "Durée d'un transitoire : τ = R·C (RC) ou L/R (RL)." },
  { t: "Régime transitoire", d: "Évolution temporaire avant le régime établi." },
  { t: "Courant alternatif", d: "Courant qui change périodiquement de sens (sinusoïdal, 50 Hz en France)." },
  { t: "Valeur efficace", d: "Valeur continue équivalente en chauffe : U_eff = U_max/√2 (sinus)." },
  { t: "Fréquence (f)", d: "Nombre de cycles par seconde, en hertz (Hz) ; pulsation ω = 2πf." },
  { t: "Déphasage (φ)", d: "Décalage entre tension et courant en alternatif." },
  { t: "Impédance (Z)", d: "« Résistance » en alternatif : Z_R = R, Z_L = jLω, Z_C = 1/(jCω)." },
  { t: "Réactance", d: "Partie « bobine/condensateur » de l'impédance (sans pertes)." },
  { t: "Résonance", d: "Fréquence où bobine et condensateur se compensent : f₀ = 1/(2π√(LC))." },
  { t: "Facteur de qualité (Q)", d: "Finesse d'une résonance (pic plus ou moins étroit)." },
  { t: "Puissance active (P)", d: "Part réellement utile en alternatif : P = U·I·cos φ (W)." },
  { t: "Puissance réactive (Q)", d: "Part échangée sans travail : Q = U·I·sin φ (VAR)." },
  { t: "Puissance apparente (S)", d: "S = U·I (VA) ; S² = P² + Q²." },
  { t: "Facteur de puissance (cos φ)", d: "Rapport P/S : la part vraiment utile de la puissance." },
  { t: "Diode", d: "Composant qui ne laisse passer le courant que dans un sens ; chute ≈ 0,7 V (silicium) quand elle conduit." },
  { t: "Tension de seuil", d: "Tension à franchir pour qu'une diode conduise (≈ 0,7 V silicium, ≈ 2 V LED rouge)." },
  { t: "LED", d: "Diode électroluminescente ; seuil ≈ 2 V (rouge) à 3,2 V (bleue) ; nécessite une résistance série." },
  { t: "Redressement", d: "Conversion d'un courant alternatif en courant à un seul sens à l'aide de diodes." },
  { t: "Pont de Graetz", d: "Redresseur double alternance à 4 diodes (2 conduisent à la fois, perte ≈ 1,4 V)." },
  { t: "Transistor (bipolaire)", d: "Composant à 3 bornes où un petit courant de base commande un grand courant collecteur." },
  { t: "Gain β", d: "Facteur d'amplification en courant d'un transistor : I_C = β·I_B (souvent 100 à 300)." },
  { t: "Saturation / blocage", d: "Les deux états « interrupteur » d'un transistor : passant à fond, ou bloqué (I ≈ 0)." },
  { t: "MOSFET", d: "Transistor commandé en tension (grille) ; en logique, conduit si V_GS dépasse un seuil." },
  { t: "AOP", d: "Amplificateur opérationnel : compare deux entrées avec un gain énorme en boucle ouverte." },
  { t: "Comparateur", d: "AOP en boucle ouverte : sortie haute si V⁺ > V⁻, basse sinon." },
  { t: "Court-circuit virtuel", d: "En boucle fermée, la contre-réaction force V⁺ ≈ V⁻ aux entrées de l'AOP." },
  { t: "Gain (montage AOP)", d: "Non inverseur : G = 1 + R_f/R_g. Inverseur : G = −R_f/R_g." },
  { t: "Filtre", d: "Circuit qui laisse passer certaines fréquences et atténue les autres (passe-bas, passe-haut…)." },
  { t: "Fréquence de coupure (f_c)", d: "Limite −3 dB d'un filtre : f_c = 1/(2π·R·C) pour un RC." },
  { t: "Décibel (dB)", d: "Échelle logarithmique du gain : G(dB) = 20·log₁₀(|sortie/entrée|) ; −3 dB ≈ ×0,707." },
  { t: "Diagramme de Bode", d: "Tracé du gain (en dB) et de la phase d'un circuit en fonction de la fréquence." },
  { t: "Diode Zener", d: "Diode qui, en inverse, maintient une tension fixe Vz : sert à réguler." },
  { t: "Régulation", d: "Maintien d'une tension de sortie stable malgré les variations d'entrée ou de charge." },
  { t: "555 (astable)", d: "Oscillateur : f ≈ 1,44/((R1+2·R2)·C)." },
  { t: "Rapport cyclique", d: "Fraction du temps où un signal est à l'état haut : temps haut ÷ période." },
  { t: "Transformateur", d: "Modifie une tension alternative selon le rapport des spires : Vs/Vp = Ns/Np ; isole et conserve la puissance." },
  { t: "Bit", d: "Plus petite unité d'information : 0 ou 1. N bits → 2^N valeurs." },
  { t: "Octet", d: "Groupe de 8 bits : 2⁸ = 256 valeurs (0 à 255)." },
  { t: "Binaire", d: "Numération en base 2 ; chaque position vaut le double de la précédente (1, 2, 4, 8…)." },
  { t: "Porte logique", d: "Circuit élémentaire appliquant une règle vrai/faux (ET, OU, NON, XOR…)." },
  { t: "Table de vérité", d: "Liste exhaustive des sorties d'un circuit logique ; 2^N lignes pour N entrées." },
  { t: "NAND", d: "NON-ET : sort 0 seulement si toutes les entrées valent 1 ; porte universelle." },
  { t: "XOR", d: "OU exclusif : sort 1 si les entrées diffèrent ; c'est le bit de somme d'un additionneur." },
  { t: "Demi-additionneur", d: "Additionne 2 bits : somme = a XOR b, retenue = a ET b." },
  { t: "Additionneur complet", d: "Additionne 3 bits (a, b, retenue entrante) ; enchaîne les colonnes d'une addition." },
  { t: "Retenue", d: "Bit reporté à la colonne suivante quand une addition dépasse 1 (1+1 = 10)." },
  { t: "Bascule D", d: "Mémorise 1 bit : au front d'horloge, Q recopie D puis le conserve." },
  { t: "Front d'horloge", d: "Instant de basculement du signal d'horloge qui déclenche la mémorisation." },
  { t: "Registre", d: "Paquet de bascules D mémorisant plusieurs bits (un nombre) à la fois." },
  { t: "Multiplexeur", d: "Aiguillage qui choisit une entrée parmi 2^k selon k lignes de sélection." },
  { t: "Compteur", d: "Avance d'un pas à chaque front ; sur N bits, compte de 0 à 2^N − 1." },
  { t: "Bus", d: "Groupe de fils transportant plusieurs bits (un nombre) en parallèle." },
  { t: "Adresse", d: "Numéro d'une case mémoire ; N bits d'adresse → 2^N cases." },
  { t: "ADC (CAN)", d: "Convertisseur analogique→numérique : code = arrondi(Vin/Vréf × (2^N − 1))." },
  { t: "Résolution (ADC)", d: "Plus petit écart de tension distingué : Vréf/2^N." },
  { t: "BCD / 7 segments", d: "Code d'un chiffre 0–9 sur 4 bits, décodé pour allumer les segments d'un afficheur." },
  { t: "Chronogramme", d: "Tracé de l'état des signaux logiques au cours du temps." },
  { t: "Complément à deux", d: "Codage des nombres signés : −x = (inversion des bits de x) + 1 ; permet de soustraire en additionnant." },
  { t: "Tri-state / haute impédance", d: "3e état d'une sortie (« débranché », ni 0 ni 1) pour partager un bus sans conflit." },
  { t: "RAM", d: "Mémoire vive à cases adressables ; capacité = nombre de cases × bits par case." },
  { t: "Opcode / jeu d'instructions", d: "Code d'une opération (sur k bits → 2^k instructions) exécutée par un processeur." },
];

function TourPanel({ readLessons, completed, onOpenLesson, onActivateMission, onDiploma, onGlossary, onJourney, chap = "elec" }) {
  const STEPS = chapData(chap).steps, CHMISS = chapData(chap).missions;
  const isDone = (st) => (st.kind === "lesson" ? readLessons.includes(st.id) : completed.includes(st.id));
  const doneCount = STEPS.filter(isDone).length, total = STEPS.length;
  const pct = Math.round((doneCount / total) * 100);
  const next = STEPS.find((st) => !isDone(st));
  const missionsAllDone = CHMISS.every((m) => completed.includes(m.id));
  const go = (st) => (st.kind === "lesson" ? onOpenLesson(st.id) : onActivateMission(st.id));
  const groupBy = (arr) => { const out = []; arr.forEach((s) => { const g = out.find((x) => x.cat === s.cat); if (g) g.items.push(s); else out.push({ cat: s.cat, items: [s] }); }); return out; };
  const lessonGroups = groupBy(STEPS.filter((s) => s.kind === "lesson"));
  const missionGroups = groupBy(STEPS.filter((s) => s.kind === "mission"));
  const lTitle = (id) => (findLesson(id) || {}).title;
  const lMini = (id) => !!(findLesson(id) || {}).mini;
  const mTitle = (id) => (findMission(id) || {}).title;
  const mDefi = (id) => !!(findMission(id) || {}).defi;
  const Row = ({ st, label, tag, tagCls }) => {
    const done = isDone(st), isNext = next === st;
    return (
      <button className={"pc-row " + (done ? "done " : "") + (isNext ? "next" : "")} onClick={() => go(st)}>
        <span className={"pc-dot " + (done ? "ok" : "")}>{done ? <Check size={12} strokeWidth={3} /> : ""}</span>
        <span className="pc-label">{label}{tag && <span className={"pc-tag " + (tagCls || "")}>{tag}</span>}</span>
        {isNext && <ChevronRight size={15} className="pc-arrow" />}
      </button>
    );
  };
  return (
    <>
      <div className="pc-head">
        <div className="pc-bar"><div className="pc-fill" style={{ width: pct + "%" }} /></div>
        <div className="pc-meta"><b className="mono">{pct}%</b> · {doneCount}/{total} étapes</div>
        {!missionsAllDone && next && (
          <button className="pc-continue" onClick={() => go(next)}>{doneCount === 0 ? "Commencer le parcours" : "Continuer"} <ChevronRight size={16} /></button>
        )}
        {missionsAllDone && <button className="pc-continue done" onClick={onDiploma}><Award size={16} /> Voir mon diplôme</button>}
      </div>
      {onJourney && (
        <div className="pc-journeys">
          <button className="pc-journey" onClick={() => onJourney("tour")}><Sparkles size={14} /> Parcours conseillé <span className="pc-journey-sub">tous les chapitres</span></button>
          {chap === "num" && <button className="pc-journey ordi" onClick={() => onJourney("ordi")}><Cpu size={14} /> Construis un ordinateur <span className="pc-journey-sub">campagne guidée</span></button>}
        </div>
      )}
      <p className="hint-line">Avance pas à pas : lis le cours, essaie le mini, puis relève la mission. Ta progression est enregistrée automatiquement.</p>
      <div className="pc-phase"><span className="pc-num">1</span> Apprendre les notions</div>
      {lessonGroups.map((g) => (
        <div className="pc-group" key={g.cat}>
          <div className="pc-cat">{g.cat}</div>
          {g.items.map((st) => <Row key={st.id} st={st} label={lTitle(st.id)} tag={lMini(st.id) ? "essai" : null} />)}
        </div>
      ))}
      <div className="pc-phase"><span className="pc-num">2</span> Se mettre à l'épreuve</div>
      {missionGroups.map((g) => (
        <div className="pc-group" key={g.cat}>
          <div className="pc-cat">{g.cat}</div>
          {g.items.map((st) => <Row key={st.id} st={st} label={mTitle(st.id)} tag={mDefi(st.id) ? "défi" : null} tagCls={mDefi(st.id) ? "defi" : ""} />)}
        </div>
      ))}
      <button className="pc-gloss" onClick={onGlossary}><BookOpen size={15} /> Ouvrir le glossaire</button>
    </>
  );
}

function GlossaryModal({ onClose }) {
  const [q, setQ] = useState("");
  const nq = deburr(q);
  const items = GLOSSARY.filter((g) => !nq || deburr(g.t).includes(nq) || deburr(g.d).includes(nq));
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal gloss-modal" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label="Glossaire">
        <div className="modal-head"><div className="modal-title"><BookOpen size={18} /> Glossaire</div><button className="modal-close" onClick={onClose} aria-label="Fermer"><X size={18} /></button></div>
        <div className="modal-body">
          <div className="list-search gloss-search">
            <Search size={14} className="ls-ic" />
            <input autoFocus type="text" placeholder="Rechercher un terme…" value={q} onChange={(e) => setQ(e.target.value)} aria-label="Rechercher un terme" />
            {q && <button className="ls-clear" onClick={() => setQ("")} aria-label="Effacer"><X size={13} /></button>}
          </div>
          {items.length === 0 && <p className="hint-line">Aucun terme ne correspond à « {q} ».</p>}
          <dl className="gloss-list">
            {items.map((g) => (<div className="gloss-item" key={g.t}><dt className="gloss-t">{g.t}</dt><dd className="gloss-d">{g.d}</dd></div>))}
          </dl>
        </div>
      </div>
    </div>
  );
}

function DiplomaModal({ onClose, missionsDone, missionsTotal, doneSteps, totalSteps, name, onName }) {
  const allDone = missionsDone >= missionsTotal;
  const today = new Date().toLocaleDateString("fr-FR", { year: "numeric", month: "long", day: "numeric" });
  const pct = Math.round((doneSteps / totalSteps) * 100);
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal dip-modal" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label="Diplôme de fin de chapitre">
        <button className="modal-close dip-x" onClick={onClose} aria-label="Fermer"><X size={18} /></button>
        {allDone ? (
          <div className="dip-cert">
            <div className="dip-seal"><Award size={36} /></div>
            <div className="dip-kicker">ÉlecLab · KingDown</div>
            <h2 className="dip-title">Diplôme d'électricité</h2>
            <p className="dip-line">Décerné à</p>
            <input className="dip-name" value={name} onChange={(e) => onName(e.target.value)} placeholder="— écris ton nom —" maxLength={40} aria-label="Ton nom" />
            <p className="dip-body">pour avoir parcouru l'intégralité du chapitre <b>Électricité</b> : les {missionsTotal} missions réussies et toutes les leçons étudiées, du circuit fermé jusqu'à la puissance en alternatif.</p>
            <div className="dip-foot"><span>Délivré le {today}</span><span className="dip-grade">Chapitre validé ✓</span></div>
          </div>
        ) : (
          <div className="dip-locked">
            <div className="dip-seal locked"><Award size={36} /></div>
            <h2 className="dip-title">Ton diplôme t'attend</h2>
            <p className="dip-body">Termine les missions du chapitre <b>Électricité</b> pour débloquer ton diplôme.</p>
            <div className="pc-bar big"><div className="pc-fill" style={{ width: pct + "%" }} /></div>
            <p className="dip-progress">{pct}% du parcours · il reste <b>{missionsTotal - missionsDone}</b> mission(s) à réussir.</p>
            <button className="dip-close-btn" onClick={onClose}>Continuer le parcours</button>
          </div>
        )}
      </div>
    </div>
  );
}

/* Non-blocking structural checks that complement diagnose(): accurately flags
   unconnected pins (incl. 3-4 pin parts) via pinsOf, and a missing ground. */
function lintCircuit(components, wires) {
  const out = [];
  if (!components.length) return out;
  const used = new Set();
  wires.forEach((w) => { used.add(w.a); used.add(w.b); });
  const ANALOG = new Set(["resistor", "pot", "motor", "lamp", "capacitor", "inductor", "diode", "led", "zener", "fuse", "ldr", "thermistor", "npn", "nmos", "pmos", "opamp", "transformer", "relay"]);
  const hasSource = components.some((c) => c.type === "battery" || c.type === "acsource");
  const hasAnalog = components.some((c) => ANALOG.has(c.type));
  const hasGround = components.some((c) => c.type === "ground");
  const dangling = [];
  for (const c of components) { for (const p of pinsOf(c)) { if (!used.has(p.id)) { dangling.push(c); break; } } }
  if (dangling.length) out.push({ level: "warn", msg: dangling.length === 1 ? "Une borne non connectée" : dangling.length + " composants ont une borne non connectée", detail: dangling.slice(0, 5).map((c) => compLabel(c, components)).join(", "), hint: "Relie chaque borne par un fil, ou supprime le composant inutilisé." });
  if (hasSource && hasAnalog && !hasGround) out.push({ level: "info", msg: "Aucune masse", hint: "Le simulateur prend une borne de source comme référence. Ajoute une masse pour des potentiels de nœud cohérents (utile avec l'affichage des tensions)." });
  return out;
}

function sweepUnit(type, field) {
  if (field === "freq") return " Hz";
  if (type === "resistor" || type === "pot" || type === "motor" || type === "relay") return " Ω";
  if (type === "battery" || type === "acsource") return " V";
  if (type === "capacitor") return " µF";
  if (type === "isource") return " A";
  if (type === "ccvs") return " Ω";
  if (type === "vccs") return " S";
  if (type === "vcvs" || type === "cccs") return "";
  return "";
}

/* DC sweep / characteristic plotter: pick a parameter to vary and a quantity to
   trace. Reuses the engine dcSweep + a small inline SVG line plot. */
function SweepModal({ components, wires, onClose }) {
  const sweepOpts = [];
  components.filter((c) => typeof c.value === "number").forEach((c) => sweepOpts.push({ key: c.id + "|value", id: c.id, field: "value", label: compLabel(c, components) + " · valeur", unit: sweepUnit(c.type, "value") }));
  components.filter((c) => c.type === "acsource").forEach((c) => sweepOpts.push({ key: c.id + "|freq", id: c.id, field: "freq", label: compLabel(c, components) + " · fréquence", unit: " Hz" }));
  const outOpts = components.filter((c) => !["ground", "in", "out", "high", "low", "clock"].includes(c.type));
  const [sweptKey, setSweptKey] = useState(sweepOpts[0] ? sweepOpts[0].key : "");
  const swept = sweepOpts.find((o) => o.key === sweptKey) || sweepOpts[0];
  const sweptComp = swept ? components.find((c) => c.id === swept.id) : null;
  const base = sweptComp ? (swept.field === "freq" ? (sweptComp.freq || 1) : (sweptComp.value || 1)) : 1;
  const [from, setFrom] = useState("0");
  const [to, setTo] = useState(String(+(base * 2).toPrecision(3) || 10));
  const [outId, setOutId] = useState((outOpts.find((c) => !["battery", "acsource"].includes(c.type)) || outOpts[0] || {}).id || "");
  const [outKind, setOutKind] = useState("V");
  useEffect(() => { setFrom("0"); setTo(String(+(base * 2).toPrecision(3) || 10)); }, [sweptKey]);
  if (!swept || !outId) return (
    <div className="modal-overlay" onClick={onClose}><div className="modal" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label="Balayage"><div className="modal-head"><div className="modal-title"><LineChart size={18} /> Balayage</div><button className="modal-close" onClick={onClose} aria-label="Fermer"><X size={18} /></button></div><div className="modal-body"><p className="hint-line">Il faut au moins un composant réglable (résistance, source…) et un composant à mesurer sur le plan.</p></div></div></div>);
  const fromN = Number(from), toN = Number(to);
  const data = (isFinite(fromN) && isFinite(toN) && toN !== fromN) ? dcSweep(components, wires, { compId: swept.id, field: swept.field, from: fromN, to: toN, steps: 90, outId, outKind }) : { points: [] };
  const pts = data.points;
  const ys = pts.map((p) => p.y);
  let yMin = Math.min(0, ...ys), yMax = Math.max(0, ...ys);
  if (!(isFinite(yMin) && isFinite(yMax)) || yMin === yMax) { yMin = (isFinite(yMin) ? yMin : 0) - 1; yMax = (isFinite(yMax) ? yMax : 0) + 1; }
  const W = 470, H = 246, pL = 56, pR = 14, pT = 14, pB = 30, pw = W - pL - pR, ph = H - pT - pB;
  const X = (x) => pL + ((x - fromN) / (toN - fromN)) * pw;
  const Y = (y) => pT + (1 - (y - yMin) / (yMax - yMin)) * ph;
  const poly = pts.map((p) => X(p.x) + "," + Y(p.y)).join(" ");
  const yFmt = (y) => outKind === "I" ? fmtA(y) : outKind === "P" ? fmtP(y) : fmtV(y);
  const outComp = components.find((c) => c.id === outId);
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label="Balayage">
        <div className="modal-head"><div className="modal-title"><LineChart size={18} /> Balayage / caractéristique</div><button className="modal-close" onClick={onClose} aria-label="Fermer"><X size={18} /></button></div>
        <div className="modal-body">
          <div className="sweep-ctrls">
            <label>Paramètre balayé<select value={sweptKey} onChange={(e) => setSweptKey(e.target.value)}>{sweepOpts.map((o) => <option key={o.key} value={o.key}>{o.label}</option>)}</select></label>
            <label>De<input type="number" value={from} onChange={(e) => setFrom(e.target.value)} /></label>
            <label>À<input type="number" value={to} onChange={(e) => setTo(e.target.value)} /></label>
            <label>Mesurer sur<select value={outId} onChange={(e) => setOutId(e.target.value)}>{outOpts.map((c) => <option key={c.id} value={c.id}>{compLabel(c, components)}</option>)}</select></label>
            <label>Grandeur<select value={outKind} onChange={(e) => setOutKind(e.target.value)}><option value="V">Tension</option><option value="I">Courant</option><option value="P">Puissance</option></select></label>
          </div>
          <svg className="sweep-plot" viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="xMidYMid meet">
            <rect x={pL} y={pT} width={pw} height={ph} className="scope-bg" rx={6} />
            {Y(0) >= pT && Y(0) <= pT + ph && <line x1={pL} y1={Y(0)} x2={pL + pw} y2={Y(0)} className="scope-zero" />}
            {pts.length > 1 && <polyline points={poly} fill="none" stroke="var(--amber)" strokeWidth={2} />}
            <text x={pL} y={H - 9} className="scope-lbl" textAnchor="start">{nf(fromN, 2) + (swept.unit || "")}</text>
            <text x={pL + pw} y={H - 9} className="scope-lbl" textAnchor="end">{nf(toN, 2) + (swept.unit || "")}</text>
            <text x={pL + pw / 2} y={H - 9} className="scope-lbl" textAnchor="middle">{swept.label}</text>
            <text x={pL - 7} y={Y(yMax) + 4} className="scope-lbl" textAnchor="end">{yFmt(yMax)}</text>
            <text x={pL - 7} y={Y(yMin) + 4} className="scope-lbl" textAnchor="end">{yFmt(yMin)}</text>
          </svg>
          <p className="hint-line">Trace {outKind === "I" ? "le courant" : outKind === "P" ? "la puissance" : "la tension"} de « {compLabel(outComp, components)} » en fonction du paramètre. Pour une caractéristique I-V, balaie une source en mesurant le courant d'une diode/LED/Zener ; pour une caractéristique de transfert, balaie l'entrée en mesurant la sortie ; ou trace P en fonction d'une résistance.</p>
        </div>
      </div>
    </div>
  );
}

function FormulaireModal({ onClose, onOpen }) {
  const [q, setQ] = useState("");
  const nq = deburr(q);
  const CHAPS = [["elec", "Électricité", LESSONS], ["electro", "Électronique", LESSONS_E], ["num", "Numérique", LESSONS_N]];
  const groups = CHAPS.map(([chap, label, lessons]) => {
    const rows = lessons.filter((l) => (l.formulas || []).length)
      .map((l) => ({ id: l.id, title: l.title, icon: l.icon, formulas: l.formulas, why: WHY[l.id] || "" }))
      .filter((r) => !nq || deburr(r.title).includes(nq) || (r.formulas || []).some((f) => deburr(f.expr).includes(nq) || deburr(f.legend || "").includes(nq)) || deburr(r.why).includes(nq));
    return { chap, label, rows };
  }).filter((g) => g.rows.length);
  const total = groups.reduce((s, g) => s + g.rows.length, 0);
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal gloss-modal" onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-label="Formulaire">
        <div className="modal-head"><div className="modal-title"><Sigma size={18} /> Formulaire</div><button className="modal-close" onClick={onClose} aria-label="Fermer"><X size={18} /></button></div>
        <div className="modal-body">
          <div className="list-search gloss-search">
            <Search size={14} className="ls-ic" />
            <input autoFocus type="text" placeholder="Rechercher une formule, une grandeur…" value={q} onChange={(e) => setQ(e.target.value)} aria-label="Rechercher une formule" />
            {q && <button className="ls-clear" onClick={() => setQ("")} aria-label="Effacer"><X size={13} /></button>}
          </div>
          {!nq && <p className="hint-line">Toutes les formules du cours, par chapitre. Clique « Ouvrir » pour la leçon et son « Pourquoi cette formule ? ».</p>}
          {total === 0 && <p className="hint-line">Aucune formule ne correspond à « {q} ».</p>}
          {groups.map((g) => (
            <div className="form-chap" key={g.chap}>
              <div className="form-chap-h">{g.label} <span className="form-chap-n">{g.rows.length}</span></div>
              {g.rows.map((r) => (
                <div className="form-card" key={r.id}>
                  <div className="form-card-top">
                    <span className="form-titre">{r.icon ? <r.icon size={14} /> : null} {r.title}</span>
                    <button className="form-open" onClick={() => onOpen(g.chap, r.id)}>Ouvrir <ChevronRight size={13} /></button>
                  </div>
                  <div className="form-eqs">
                    {r.formulas.map((f, i) => (<div className="form-eq" key={i}><span className="mono form-expr">{f.expr}</span>{f.legend ? <span className="form-leg">{f.legend}</span> : null}</div>))}
                  </div>
                </div>
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function MissionsList({ active, setActive, completed, chap = "elec" }) {
  const D = chapData(chap);
  const [q, setQ] = useState("");
  const nq = deburr(q);
  const match = (m) => !nq || deburr(m.title).includes(nq) || deburr(m.short).includes(nq) || deburr(m.chapter).includes(nq);
  const chaps = D.chapters.map((chapName) => [chapName, D.missions.filter((m) => m.chapter === chapName && match(m))]).filter(([, ms]) => ms.length);
  return (
    <>
      <div className="list-search">
        <Search size={14} className="ls-ic" />
        <input type="text" placeholder="Rechercher une mission…" value={q} onChange={(e) => setQ(e.target.value)} aria-label="Rechercher une mission" />
        {q && <button className="ls-clear" onClick={() => setQ("")} aria-label="Effacer la recherche"><X size={13} /></button>}
      </div>
      {chaps.length === 0 && <p className="hint-line">Aucune mission ne correspond à « {q} ».</p>}
      {chaps.map(([chap, ms]) => (
        <div key={chap} className="cat">
          <div className="cat-title"><ListChecks size={13} /> {chap}</div>
          {ms.map((m) => {
            const done = completed.includes(m.id), act = active === m.id;
            return (
              <button key={m.id} className={"mission-row " + (act ? "act " : "") + (done ? "done" : "")} onClick={() => setActive(m.id)} aria-pressed={act}>
                <span className={"m-check " + (done ? "ok" : "")} aria-hidden="true">{done ? <Check size={13} strokeWidth={3} /> : ""}</span>
                <span className="m-text"><span className="m-titre">{m.title}</span><span className="m-court">{m.short}</span></span>
              </button>
            );
          })}
        </div>
      ))}
      {!nq && (
        <button className={"mission-row " + (active === "sandbox" ? "act" : "")} onClick={() => setActive("sandbox")} aria-pressed={active === "sandbox"}>
          <span className="m-check sb" aria-hidden="true"><Sparkles size={13} /></span>
          <span className="m-text"><span className="m-titre">Bac à sable</span><span className="m-court">Construis librement</span></span>
        </button>
      )}
    </>
  );
}

function LessonsList({ onOpen, current, onGlossary, onFormulaire, read = [], resumeId, onResume, chap = "elec" }) {
  const D = chapData(chap);
  const readCount = D.lessons.filter((l) => read.includes(l.id)).length;
  const total = D.lessons.length;
  const pct = total ? Math.round((readCount / total) * 100) : 0;
  const resumeLesson = resumeId ? findLesson(resumeId) : null;
  const [q, setQ] = useState("");
  const nq = deburr(q);
  const match = (l) => !nq || deburr(l.title).includes(nq) || deburr(l.keyIdea).includes(nq) || (l.paragraphs || []).some((p) => deburr(p).includes(nq));
  const cats = D.cats.map(([cat, ids]) => [cat, ids.filter((id) => { const l = D.lessons.find((x) => x.id === id); return l && match(l); })]).filter(([, ids]) => ids.length);
  return (
    <>
      {resumeLesson && onResume && <button className="list-resume" onClick={onResume}><RotateCcw size={13} /> Reprendre : <b>{resumeLesson.title}</b></button>}
      <div className="list-prog">
        <div className="list-prog-bar"><div className="list-prog-fill" style={{ width: pct + "%" }} /></div>
        <span className="list-prog-txt"><b className="mono">{readCount}</b>/{total} leçons lues</span>
      </div>
      <div className="list-search">
        <Search size={14} className="ls-ic" />
        <input type="text" placeholder="Rechercher une leçon…" value={q} onChange={(e) => setQ(e.target.value)} aria-label="Rechercher une leçon" />
        {q && <button className="ls-clear" onClick={() => setQ("")} aria-label="Effacer la recherche"><X size={13} /></button>}
      </div>
      {(onGlossary || onFormulaire) && <div className="list-tools">{onFormulaire && <button className="list-gloss" onClick={onFormulaire}><Sigma size={14} /> Formulaire</button>}{onGlossary && <button className="list-gloss" onClick={onGlossary}><BookOpen size={14} /> Glossaire des termes</button>}</div>}
      {!nq && <p className="hint-line">De petites leçons illustrées, avec un curseur de niveau (du débutant au Master) dans chaque cours.</p>}
      {cats.length === 0 && <p className="hint-line">Aucune leçon ne correspond à « {q} ».</p>}
      {cats.map(([cat, ids]) => (
        <div className="lesson-cat" key={cat}>
          <div className="lesson-cat-h">{cat}</div>
          {ids.map((id) => {
            const l = D.lessons.find((x) => x.id === id);
            if (!l) return null;
            return (
              <button key={l.id} className={"lesson-row " + (current === l.id ? "act" : "")} onClick={() => onOpen(l.id)}>
                <span className="lesson-ic"><l.icon size={16} /></span>
                <span className="m-text"><span className="m-titre">{l.title}</span><span className="m-court">{l.keyIdea}</span></span>
                <ChevronRight size={15} className="pi-plus" />
              </button>
            );
          })}
        </div>
      ))}
    </>
  );
}

function Readouts({ rows }) {
  return (
    <div className="ro-grid">
      {rows.map(([k, v, cls]) => (
        <div className="ro-row" key={k}><span className="ro-k">{k}</span><span className={"ro-v mono " + (cls || "")}>{v}</span></div>
      ))}
    </div>
  );
}

