function OhmWheel() {
  const cx = 160, cy = 160, rHub = 64, ri = 73, ro = 151, rText = 112;
  const pol = (r, d) => [cx + r * Math.cos((d * Math.PI) / 180), cy + r * Math.sin((d * Math.PI) / 180)];
  const sector = (a0, a1) => {
    const [x0o, y0o] = pol(ro, a0), [x1o, y1o] = pol(ro, a1), [x1i, y1i] = pol(ri, a1), [x0i, y0i] = pol(ri, a0);
    return `M${x0o} ${y0o} A${ro} ${ro} 0 0 1 ${x1o} ${y1o} L${x1i} ${y1i} A${ri} ${ri} 0 0 0 ${x0i} ${y0i} Z`;
  };
  const wedge = (a0, a1) => {
    const [x0, y0] = pol(rHub, a0), [x1, y1] = pol(rHub, a1);
    return `M${cx} ${cy} L${x0} ${y0} A${rHub} ${rHub} 0 0 1 ${x1} ${y1} Z`;
  };
  const Q = [
    { L: "P", u: "W", col: "var(--amber)", a0: 180, f: ["P = U·I", "P = R·I²", "P = U²/R"] },
    { L: "U", u: "V", col: "var(--cyan)", a0: 270, f: ["U = R·I", "U = P/I", "U = √(P·R)"] },
    { L: "R", u: "Ω", col: "#a78bfa", a0: 0, f: ["R = U/I", "R = U²/P", "R = P/I²"] },
    { L: "I", u: "A", col: "var(--green)", a0: 90, f: ["I = U/R", "I = P/U", "I = √(P/R)"] },
  ];
  return (
    <svg viewBox="0 0 320 320" className="wheel-svg" role="img" aria-label="Cercle de la loi d'Ohm : les douze formules reliant puissance, tension, intensité et résistance">
      {Q.map((q) => q.f.map((f, j) => {
        const a0 = q.a0 + 30 * j, a1 = a0 + 30, [tx, ty] = pol(rText, a0 + 15);
        return (
          <g key={q.L + j}>
            <path d={sector(a0, a1)} fill={q.col} fillOpacity="0.14" stroke={q.col} strokeOpacity="0.55" strokeWidth="1.3" />
            <text x={tx} y={ty} className="wheel-f" textAnchor="middle" dominantBaseline="central">{f}</text>
          </g>
        );
      }))}
      {Q.map((q) => {
        const [tx, ty] = pol(34, q.a0 + 45);
        return (
          <g key={"h" + q.L}>
            <path d={wedge(q.a0, q.a0 + 90)} fill={q.col} fillOpacity="0.2" stroke="var(--bg-2)" strokeWidth="2" />
            <text x={tx} y={ty} className="wheel-l" fill={q.col} textAnchor="middle" dominantBaseline="central">{q.L}</text>
            <text x={tx} y={ty + 16} className="wheel-u" textAnchor="middle" dominantBaseline="central">{q.u}</text>
          </g>
        );
      })}
      <circle cx={cx} cy={cy} r={rHub} fill="none" stroke="var(--cyan)" strokeOpacity="0.25" strokeWidth="1.4" />
      <line x1={cx - ro} y1={cy} x2={cx + ro} y2={cy} stroke="var(--bg-2)" strokeWidth="2.2" />
      <line x1={cx} y1={cy - ro} x2={cx} y2={cy + ro} stroke="var(--bg-2)" strokeWidth="2.2" />
    </svg>
  );
}

function PowerTriangle() {
  const [cphi, setCphi] = useState(0.8);
  const phi = Math.acos(Math.min(1, Math.max(0.05, cphi)));
  const S = 1000, P = Math.round(S * Math.cos(phi)), Q = Math.round(S * Math.sin(phi));
  const ox = 50, oy = 176, L = 166;
  const ax = ox + L * Math.cos(phi), ay = oy, bx = ax, by = oy - L * Math.sin(phi);
  const ar = 32, arcx = ox + ar * Math.cos(phi), arcy = oy - ar * Math.sin(phi);
  return (
    <div className="tri">
      <svg viewBox="0 0 320 206" className="tri-svg" role="img" aria-label="Triangle des puissances : active, réactive et apparente">
        <line x1={ox} y1={oy} x2={ax} y2={ay} stroke="var(--cyan)" strokeWidth="5" strokeLinecap="round" />
        <line x1={ax} y1={ay} x2={bx} y2={by} stroke="var(--amber)" strokeWidth="5" strokeLinecap="round" />
        <line x1={ox} y1={oy} x2={bx} y2={by} stroke="var(--green)" strokeWidth="5" strokeLinecap="round" />
        <path d={"M " + (ox + ar) + " " + oy + " A " + ar + " " + ar + " 0 0 0 " + arcx + " " + arcy} fill="none" stroke="var(--muted)" strokeWidth="1.6" />
        <text x={ox + ar + 7} y={oy - 7} className="tri-phi" fill="var(--muted)">φ</text>
        <text x={(ox + ax) / 2} y={oy + 19} className="tri-lab" fill="var(--cyan)" textAnchor="middle">P = {P} W</text>
        <text x={ax + 9} y={(ay + by) / 2} className="tri-lab" fill="var(--amber)" dominantBaseline="central">Q = {Q} VAR</text>
        <text x={(ox + bx) / 2 - 8} y={(oy + by) / 2 - 9} className="tri-lab" fill="var(--green)" textAnchor="end">S = {S} VA</text>
      </svg>
      <label className="mini-slider">
        <span>Facteur de puissance cos φ : <b className="mono">{cphi.toFixed(2)}</b></span>
        <input type="range" min="0.3" max="1" step="0.05" value={cphi} onChange={(e) => setCphi(Number(e.target.value))} />
      </label>
      <div className="mini-readout">À cos φ = {cphi.toFixed(2)}, sur {S} VA appelés au réseau, seuls <b>{P} W</b> travaillent vraiment ; {Q} VAR font des allers-retours sans rien produire.</div>
    </div>
  );
}

