  nor: { label: "NON-OU (NOR)", sym: "S = E1 + E2‾", n: 2, f: (a, b) => (a | b ? 0 : 1) },
  xor: { label: "OU exclusif (XOR)", sym: "S = E1 ⊕ E2", n: 2, f: (a, b) => a ^ b },
  xnor: { label: "NON-OU-X (XNOR)", sym: "S = E1 ⊕ E2‾", n: 2, f: (a, b) => (a ^ b ? 0 : 1) },
